/// The main entry point for the kernel. This function will be called by _start() in architecture-specific assembly code after the kernel is loaded into memory.
/// # Arguments
/// * `a0` - a0 register value passed from the bootloader, storing the hart ID of the booting CPU (for RISC-V) or argc the argument count (for LoongArch64).
/// * `a1` - a1 register value passed from the bootloader, storing the address of the device tree blob (DTB) (for RISC-V) or a pointer to the array of arguments (for LoongArch64).
/// * `a2` - a2 register value passed from the bootloader, storing the environment pointer (for LoongArch64), for RISC-V architecture definition this is reserved for future use, so no specific usage here.
fn main(a0: u64, a1: u64, a2: u64) -> ! {
    // Clear the .bss section before doing anything else, to ensure that all static variables are properly initialized to zero.
    util::clear_bss();
    crate::arch::shared::hart::bootstrap_hart_local(a0 as usize);
    crate::arch::interrupts_disable();

    log::init();
    log::add_channel(log::UART_CHANNEL, log::LogLevel::Trace);

    let _ = a2;
    let boot_info = unsafe { boot::init_boot_info(a0, a1) };
    mm::init(boot_info);
    mm::heap_init();
    mm::init_kernel_space(boot_info);

    // Try to mount a disk-backed root filesystem from virtio-blk.
    // Falls back to ramfs if no virtio-blk device is found.
    let dtb_ptr = boot_info.dtb_ptr;
    if dtb_ptr != 0 {
        let blk_addrs = boot::find_virtio_blk_mmio(dtb_ptr);
        if !blk_addrs.is_empty() {
            let mut blk_idx = b'a';
            for &blk_addr in &blk_addrs {
                let page_start = blk_addr & !(crate::mm::PAGE_SIZE - 1);
                let page_end = page_start + crate::mm::PAGE_SIZE;
                if let Some(ks) = crate::mm::kernel_space() {
                    use crate::mm::MapPermission;
                    ks.map_identical(
                        page_start as u64,
                        page_end as u64,
                        MapPermission::READ | MapPermission::WRITE,
                    );
                }
                if let Some(blk) =
                    unsafe { crate::arch::shared::virtio_blk::VirtioBlk::init(blk_addr) }
                {
                    let dev: alloc::sync::Arc<dyn crate::fs::block::BlockDevice> =
                        alloc::sync::Arc::new(blk);
                    // Register as a block device in devfs.
                    {
                        let dev_name = alloc::format!("vd{}", blk_idx as char);
                        let blk_vnode: alloc::sync::Arc<dyn crate::fs::Vnode> =
                            alloc::sync::Arc::new(crate::fs::devfs::BlockDevVnode::new(
                                alloc::sync::Arc::clone(&dev),
                            ));
                        crate::fs::devfs::register_device(
                            &dev_name,
                            crate::fs::devfs::DeviceType::Block,
                            blk_vnode,
                        );
                        info!("devfs: registered block device {}", dev_name);
                    }
                    match crate::fs::ext4::mount_ext4(dev) {
                        Ok(root_node) => {
                            crate::fs::set_root(root_node);
                            info!("mounted ext4 root from virtio-blk at {:#x}", blk_addr);
                        }
                        Err(e) => {
                            warn!(
                                "failed to mount ext4 from virtio-blk at {:#x}: {:?}",
                                blk_addr, e
                            );
                        }
                    }
                    blk_idx += 1u8;
                }
            }
        }
    }

    #[cfg(target_arch = "loongarch64")]
    if !crate::fs::is_initialized() {
        let mut blk_idx = b'a';
        for blk in crate::arch::shared::virtio_blk_pci::VirtioBlkPci::discover() {
            let dev: alloc::sync::Arc<dyn crate::fs::block::BlockDevice> =
                alloc::sync::Arc::new(blk);
            let dev_name = alloc::format!("vd{}", blk_idx as char);
            let blk_vnode: alloc::sync::Arc<dyn crate::fs::Vnode> = alloc::sync::Arc::new(
                crate::fs::devfs::BlockDevVnode::new(alloc::sync::Arc::clone(&dev)),
            );
            crate::fs::devfs::register_device(
                &dev_name,
                crate::fs::devfs::DeviceType::Block,
                blk_vnode,
            );
            info!("devfs: registered PCI block device {}", dev_name);
            match crate::fs::ext4::mount_ext4(dev) {
                Ok(root_node) => {
                    crate::fs::set_root(root_node);
                    info!(
                        "mounted ext4 root from virtio-pci block device {}",
                        dev_name
                    );
                    break;
                }
                Err(e) => {
                    warn!(
                        "failed to mount ext4 from virtio-pci block device {}: {:?}",
                        dev_name, e
                    );
                }
            }
            blk_idx += 1u8;
        }
    }

    // Fall back to ramfs if no disk filesystem was mounted.
    if !crate::fs::is_initialized() {
        crate::fs::init();
    }

    // Mount devfs at /dev and register known devices.
    {
        // Ensure /dev exists in the root filesystem so readdir("/")
        // shows the directory. Mount resolution handles lookups into
        // /dev even without this, but the directory entry makes devfs
        // visible in the parent listing.
        match crate::fs::lookup("/dev") {
            Ok(node) => {
                let meta = node.metadata().expect("failed to stat /dev");
                if meta.kind != crate::fs::NodeKind::Directory {
                    panic!("/dev exists but is not a directory");
                }
            }
            Err(crate::fs::FsError::NotFound) => {
                // Try to create /dev in the root filesystem so readdir("/")
                // shows it. If the root is a read-only or full ext4 disk,
                // this can fail (ENOSPC). That's non-fatal: mount resolution
                // handles lookups into /dev even without this directory entry.
                if let Err(e) = crate::fs::mkdir("/dev") {
                    warn!(
                        "fs: failed to mkdir /dev (mount resolution still works): {:?}",
                        e
                    );
                }
            }
            Err(e) => {
                panic!("failed to lookup /dev: {:?}", e);
            }
        }
        let devfs_root = crate::fs::devfs::devfs_root();
        crate::fs::mount::register_mount("/dev", devfs_root, crate::fs::mount::FsType::Devfs);
        crate::fs::mount::register_mount(
            "/dev/shm",
            crate::fs::ramfs::root(),
            crate::fs::mount::FsType::Ramfs,
        );
        crate::fs::devfs::register_device(
            "console",
            crate::fs::devfs::DeviceType::Char,
            crate::fs::console::console_node(),
        );
        crate::fs::devfs::register_device(
            "null",
            crate::fs::devfs::DeviceType::Char,
            crate::fs::devfs::null_node(),
        );
        crate::fs::devfs::register_device(
            "zero",
            crate::fs::devfs::DeviceType::Char,
            crate::fs::devfs::zero_node(),
        );
        crate::fs::devfs::register

