//! Competition test runner.
//!
//! Scans the root filesystem for `*_testcode.sh` scripts and runs them
//! sequentially via `/busybox sh`, printing the required
//! "#### OS COMP TEST GROUP ..." markers.
//!
//! When all tests complete, the system is powered off via the architecture's
//! reboot mechanism (QEMU test-device exit / ACPI GED).

use alloc::string::String;
use alloc::sync::Arc;
use alloc::vec;
