const TEST_GROUP_TIMEOUT_NS: u64 = 600_000_000_000;
const TEST_GROUP_TIMEOUT_YIELDS: usize = 25_000_000;

/// Write bytes to a user-space virtual address through the MemorySet.
fn write_mm_bytes(mm: &crate::mm::MemorySet, va: u64, data: &[u8]) -> Option<()> {
    for (i, &b) in data.iter().enumerate() {
        let pa = mm.translate(va + i as u64)?;
        unsafe {
            (pa as *mut u8).write_volatile(b);
        }
    }
    Some(())
}

/// Write a u64 (little-endian) to a user-space virtual address.
fn write_mm_u64(mm: &crate::mm::MemorySet, va: u64, val: u64) -> Option<()> {
    write_mm_bytes(mm, va, &val.to_le_bytes())
}

fn zero_mm_range(mm: &crate::mm::MemorySet, mut va: u64, mut len: usize) -> Option<()> {
    const ZERO_CHUNK: [u8; 256] = [0; 256];
    while len > 0 {
        let n = len.min(ZERO_CHUNK.len());
        write_mm_bytes(mm, va, &ZERO_CHUNK[..n])?;
        va = va.checked_add(n as u64)?;
        len -= n;
    }
    Some(())
}

const AT_PHDR: u64 = 3;
const AT_PHENT: u64 = 4;
