const AT_PLATFORM: u64 = 15;
const AT_CLKTCK: u64 = 17;
const AT_SECURE: u64 = 23;
const AT_RANDOM: u64 = 25;
const AT_HWCAP: u64 = 16;
const AT_EXECFN: u64 = 31;
const AT_NULL: u64 = 0;

/// Build the initial user stack for execve-style launch.
///
/// Layout (low → high, where low = SP entry):
///   argc          (8 bytes)
///   argv[]        (argc × 8 bytes, filled after string data is written)
///   NULL          (argv terminator)
///   envp[]        (envp_count × 8 bytes, filled after string data is written)
///   NULL          (envp terminator)
///   auxv[]        (n_auxv × 16 bytes)
///   string data   (random[16], platform[NUL], argv strings[NUL], envp strings[NUL], execfn[NUL])
///
/// Returns the stack pointer value (address of argc).
#[inline(never)]
fn build_user_stack(
    mm: &mut crate::mm::MemorySet,
    stack_top: usize,
    exec_path: &[u8],
    argv: &[&[u8]],
    argc: usize,
    envp: &[&[u8]],
    info: &crate::loader::LoadInfo,
) -> Option<u64> {
    // String data sizes.
    let mut string_data_size = 0usize;
    for s in argv {
        string_data_size = string_data_size.saturating_add(s.len().saturating_add(1));
    }
    for s in envp {
        string_data_size = string_data_size.saturating_add(s.len().saturating_add(1));
    }
    let random_size = 16usize;
    let platform: &[u8] = crate::arch::UNAME_MACHINE;
    let platform_size = platform.len().saturating_add(1);
    let execfn_size = exec_path.len().saturating_add(1);
    string_data_size = string_data_size
        .saturating_add(random_size)
        .saturating_add(platform_size)
        .saturating_add(execfn_size);

    // Auxv: 18 entries (matching sys_execve) each 2×u64 = 16 bytes.
    const N_AUXV: usize = 18;
    let auxv_size = N_AUXV * 16;

    let envp_count = envp.len();
    // Pointer area: argc + argv[] + NULL + envp[] + NULL.
    let pointer_area_size = 8usize
        .saturating_add(argc.saturating_mul(8))
        .saturating_add(8) // argv NULL
        .saturating_add(envp_count.saturating_mul(8))
        .saturating_add(8); // envp NULL

    let total_size = string_data_size
        .saturating_add(auxv_size)
        .saturating_add(pointer_area_size);
    if total_size > crate::mm::memory_set::USER_STACK_SIZE {
        return None;
    }

    let pad = (16 - total_size % 16) % 16;
    let total_size = total_size.saturating_add(pad);
    let sp_base = (stack_top as u64).saturating_sub(total_size as u64);
    let mut cur = sp_base;

    // 1. argc
    write_mm_u64(mm, cur, argc as u64)?;
    cur = cur.saturating_add(8);

    // 2. argv[] — write placeholders, fill after strings.
    let argv_ptr_base = cur;
    cur = cur.saturating_add((argc * 8) as u64);
    // argv NULL terminator
    write_mm_u64(mm, cur, 0)?;
    cur = cur.saturating_add(8);

    // 3. envp[] — write placeholders, fill after strings.
    let envp_ptr_base = cur;
    cur = cur.saturating_add((envp_count * 8) as u64);
    // envp NULL terminator
    write_mm_u64(mm, cur, 0)?;
    cur = cur.saturating_add(8);

    // 4. Auxv entries
    // Build deterministic "random" seed based on process info for AT_RANDOM.
    let random_payload = make_random_bytes(info, argc);
    let mut str_cur;

    // Pre-calculate string pointers.
    // Layout after auxv: argv strings, then envp strings, then random/platform/execfn.
    {
        let mut tmp = cur.saturating_add(auxv_size as u64);
        let argv_strs_size: u64 = argv.iter().fold(0u64, |acc, s| {
            acc.saturating_add(s.len() as u64).saturating_add(1)
        });
        tmp = tmp.saturating_add(argv_strs_size);
        let envp_strs_size: u64 = envp.iter().fold(0u64, |acc, s| {
            acc.saturating_add(s.len() as u64).saturating_add(1)
        });
        tmp = tmp.saturating_add(envp_strs_size);
        let random_ptr = tmp;
        tmp = tmp.saturating_add(random_size as u64);
        let platform_ptr = tmp;
        tmp = tmp.saturating_add(platform_size as u64);
        let execfn_ptr = tmp;

        // AT_PHDR
        write_mm_u64(mm, cur, AT_PHDR)?;
        cur = cur.saturating_add(8);
        write_mm_u64(mm, cur, info.phdr as u64)?;
        cur = cur.saturating_add(8);
        // AT_PHENT
        write_mm_u64(mm, cur, AT_PHENT)?;
        cur = cur.saturating_add(8);
        write_mm_u64(mm, cur, info.phent as u64)?;
        cur = cur.saturating_add(8);
        // AT_PHNUM
        write_mm_u64(mm, cur, AT_PHNUM)?;
        cur = cur.saturating_add(8);
        write_mm_u64(mm, cur, info.phnum as u64)?;
        cur = cur.saturating_add(8);
        // AT_PAGESZ
        write_mm_u64(mm, cur, AT_PAGESZ)?;
        cur = cur.saturating_add(8);
        write_mm_u64(mm, cur, info.pagesz as u64)?;
        cur = cur.saturating_add(8);
        // AT_BASE (0 for static)
        write_mm_u64(mm, cur, AT_BASE)?;
        cur = cur.saturating_add(8);
        write_mm_u64(mm, cur, 0)?;
        cur = cur.saturating_add(8);
        // AT_FLAGS
        write_mm_u64(mm, cur, AT_FLAGS)?;
        cur = cur.saturating_add(8);
        write_mm_u64(mm, cur, 0)?;
        cur = cur.saturating_add(8);
        // AT_ENTRY
        write_mm_u64(mm, cur, AT_ENTRY)?;
        cur = cur.saturating_add(8);
        write_mm_u64(mm, cur, info.entry_point as u64)?;
        cur = cur.saturating_add(8);
        // AT_UID / AT_EUID
        write_mm_u64(mm, cur, AT_UID)?;
        cur = cur.saturating_add(8);
        write_mm_u64(mm, cur, 0)?;
        cur = cur.saturating_add(8);
        write_mm_u64(mm, cur, AT_EUID)?;
        cur = cur.saturating_add(8);
