//! System call dispatch via static table.
//!
//! Syscall number in a7 (register 17). Return value written to a0 (register 10).
//! Negative return values are errno codes.
//!
//! ## Layering
//!
//! - `syscall/` (here): architecture-independent syscall numbers, dispatch
//!   table, argument validation, software semantics.
//! - `arch/shared/syscall`: `SyscallRequest` type, `request_from_regs`.
//! - `arch/{riscv64,loongarch64}/syscall`: ABI register mapping and return-PC
//!   handling (`extract_request`, `complete_syscall`).

use crate::arch::shared::syscall::SyscallRequest;

mod epoll;
mod fd;
mod io;
mod ipc;
pub(crate) mod memory;
mod mount;
mod poll;
mod process;
mod sched;
mod signal;
mod socket;
