mod timerfd;

pub mod errno;
pub mod numbers;

/// Total number of syscall slots in the dispatch table.
const NR_SYSCALLS: usize = 512;

type SyscallHandler = fn(&SyscallRequest) -> isize;

/// Full syscall dispatch table.
///
/// Unimplemented entries return `-ENOSYS` (Linux convention).
/// Only P0 syscalls have real implementations; the rest are stubs.
static SYSCALL_TABLE: [SyscallHandler; NR_SYSCALLS] = {
    let mut table: [SyscallHandler; NR_SYSCALLS] = [sys_not_implemented; NR_SYSCALLS];

    // ── P0: I/O ──
    table[numbers::SYS_IO_SETUP] = stubs::sys_enosys;
    table[numbers::SYS_IO_DESTROY] = stubs::sys_enosys;
    table[numbers::SYS_IO_SUBMIT] = stubs::sys_enosys;
    table[numbers::SYS_IO_CANCEL] = stubs::sys_enosys;
    table[numbers::SYS_IO_GETEVENTS] = stubs::sys_enosys;
    table[numbers::SYS_READ] = io::sys_read;
    table[numbers::SYS_WRITE] = io::sys_write;
    table[numbers::SYS_READV] = io::sys_readv;
    table[numbers::SYS_WRITEV] = io::sys_writev;
    table[numbers::SYS_PREAD64] = io::sys_pread64;
    table[numbers::SYS_PWRITE64] = io::sys_pwrite64;

    // ── P0: Process ──
    table[numbers::SYS_EXIT] = process::sys_exit;
    table[numbers::SYS_EXIT_GROUP] = process::sys_exit_group;
    table[numbers::SYS_GETPID] = process::sys_getpid;
    table[numbers::SYS_GETPPID] = process::sys_getppid;
    table[numbers::SYS_GETTID] = process::sys_gettid;

    // ── P0: Memory ──
    table[numbers::SYS_BRK] = memory::sys_brk;
    table[numbers::SYS_MMAP] = memory::sys_mmap;
    table[numbers::SYS_MUNMAP] = memory::sys_munmap;

    // ── P0: Time ──
    table[numbers::SYS_CLOCK_GETTIME] = time::sys_clock_gettime;
    table[numbers::SYS_GETTIMEOFDAY] = time::sys_gettimeofday;
    table[numbers::SYS_NANOSLEEP] = time::sys_nanosleep;
    table[numbers::SYS_CLOCK_GETRES] = time::sys_clock_getres;
    table[numbers::SYS_CLOCK_NANOSLEEP] = time::sys_clock_nanosleep;
    table[numbers::SYS_GETITIMER] = time::sys_getitimer;
    table[numbers::SYS_SETITIMER] = time::sys_setitimer;

    // ── P1: Scheduler ──
    table[numbers::SYS_SCHED_YIELD] = process::sys_sched_yield;
    table[numbers::SYS_SET_TID_ADDRESS] = sched::sys_set_tid_address;
    table[numbers::SYS_FUTEX] = sched::sys_futex;
    table[numbers::SYS_SET_ROBUST_LIST] = sched::sys_set_robust_list;
    table[numbers::SYS_GET_ROBUST_LIST] = sched::sys_get_robust_list;

    // ── New futex syscalls ──
    table[numbers::SYS_FUTEX_WAITV] = sched::sys_futex_waitv;
    table[numbers::SYS_FUTEX_WAKE] = sched::sys_futex_wake;
    table[numbers::SYS_FUTEX_WAIT] = sched::sys_futex_wait;
    table[numbers::SYS_FUTEX_REQUEUE] = sched::sys_futex_requeue;

    // ── P1: Process lifecyle ──
    table[numbers::SYS_CLONE] = sched::sys_clone;
    table[numbers::SYS_CLONE3] = sched::sys_clone3;
    table[numbers::SYS_EXECVE] = sched::sys_execve;
    table[numbers::SYS_WAITID] = sched::sys_waitid;
    table[numbers::SYS_WAIT4] = sched::sys_wait4;

    // ── P1: FD / VFS ──
    table[numbers::SYS_OPENAT] = fd::sys_openat;
    table[numbers::SYS_CLOSE] = fd::sys_close;
    table[numbers::SYS_LSEEK] = fd::sys_lseek;
    table[numbers::SYS_NEWFSTATAT] = fd::sys_newfstatat;
    table[numbers::SYS_FSTAT] = fd::sys_fstat;
    table[numbers::SYS_GETDENTS64] = fd::sys_getdents64;
    table[numbers::SYS_GETCWD] = fd::sys_getcwd;
    table[numbers::SYS_CHDIR] = fd::sys_chdir;
    table[numbers::SYS_READLINKAT] = fd::sys_readlinkat;
    table[numbers::SYS_DUP] = fd::sys_dup;
    table[numbers::SYS_DUP3] = fd::sys_dup3;
    table[numbers::SYS_FCNTL] = fd::sys_fcntl;
    table[numbers::SYS_IOCTL] = fd::sys_ioctl;

    // ── Mount ──
    table[numbers::SYS_UMOUNT2] = mount::sys_umount2;
    table[numbers::SYS_MOUNT] = mount::sys_mount;

    // ── P1: Pipe / IPC ──
    table[numbers::SYS_PIPE2] = ipc::sys_pipe2;

    // ── P1: Signal ──
    table[numbers::SYS_RT_SIGACTION] = signal::sys_rt_sigaction;
    table[numbers::SYS_RT_SIGPROCMASK] = signal::sys_rt_sigprocmask;
    table[numbers::SYS_RT_SIGRETURN] = signal::sys_rt_sigreturn;

    // ── P2: Memory ──
    table[numbers::SYS_MPROTECT] = memory::sys_mprotect;
    table[numbers::SYS_MREMAP] = memory::sys_mremap;

    // ── P2: Signal advanced ──
    table[numbers::SYS_KILL] = signal::sys_kill;
    table[numbers::SYS_TKILL] = signal::sys_tkill;
    table[numbers::SYS_TGKILL] = signal::sys_tgkill;
