//! Process and thread management.
//!
//! Process = resource container (address space, files).
//! Thread = schedulable execution context (registers, stack, state).
//!
//! The scheduler operates on Thread via Tid. Process provides the address
//! space token for MMU switching.

pub mod process_table;
pub mod thread_table;

