// ---------------------------------------------------------------------------
// ThreadState
// ---------------------------------------------------------------------------

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum ThreadState {
    Ready,
    Running,
    Blocked,
    Exited,
    Zombie,
}

// ---------------------------------------------------------------------------
// PID / TID types
// ---------------------------------------------------------------------------

pub type Pid = u32;
pub type Tid = u32;

static NEXT_PID: AtomicU32 = AtomicU32::new(1);
static NEXT_TID: AtomicU32 = AtomicU32::new(1);

pub fn alloc_pid() -> Pid {
    loop {
        let pid = NEXT_PID.fetch_add(1, Ordering::Relaxed);
        if pid != 0 && PROCESS_TABLE.get(pid as usize).is_none() {
            return pid;
        }
    }
}

fn alloc_tid() -> Tid {
    NEXT_TID.fetch_add(1, Ordering::Relaxed)
}

// ---------------------------------------------------------------------------
// Process
// ---------------------------------------------------------------------------

pub struct Process {
    pub pid: Pid,
    pub name: &'static str,
    pub parent: Option<Arc<SpinMutex<Process>>>,
    pub children: Vec<Arc<SpinMutex<Process>>>,
    pub mm: Option<MemorySet>,
    pub threads: Vec<Arc<SpinMutex<Thread>>>,
    pub exit_status: Option<ExitStatus>,
    /// Lock-free run token: 0 when no thread is Running, otherwise the
    /// tid of the single Running thread. CAS'd by schedule() to enforce
    /// the one-Running-thread-per-process invariant without holding the
    /// Process lock across sibling thread locks.
    pub running_tid: AtomicU32,
    /// Trap frame to free after the next remap_trap_context() replaces
    /// the PTE. Set by cleanup_thread_resources for non-last-thread exits.
    pub pending_free_trap_pa: Option<u64>,
    /// Per-process file descriptor table.
    pub files: Option<Arc<crate::fs::file_table::FileTable>>,
    /// Program break (end of the data segment).
    pub brk: u64,
    /// Lowest valid program break. brk() requests below this must not unmap
    /// ELF/data mappings that precede the heap.
    pub brk_base: u64,
    /// Anonymous mmap allocation cursor. Advances after each MAP_ANONYMOUS
    /// allocation to avoid mapping collisions.
    pub mmap_cursor: u64,
    /// Current working directory.
    pub cwd: alloc::string::String,
    /// Per-signal handler dispositions (process-wide per POSIX).
    pub signal_actions: [crate::signal::SigAction; crate::signal::SIG_N],
    /// Zombie children awaiting reaping by the parent via wait4/waitid.
    pub zombie_children: Vec<(Pid, ExitStatus)>,
    /// Threads blocked in wait4/waitid waiting for a child to become zombie.
    pub child_waiters: Vec<Tid>,
    /// Real user ID.
    pub uid: u32,
    /// Effective user ID.
    pub euid: u32,
    /// Real group ID.
    pub gid: u32,
    /// Effective group ID.
    pub egid: u32,
    /// File mode creation mask (umask).
    pub umask: u32,
