    pub fsuid: u32,
    /// Filesystem GID.
    pub fsgid: u32,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum ExitStatus {
    Exited(u8),
    Signaled(u8),
}

impl ExitStatus {
    pub fn from_exit_code(code: isize) -> Self {
        Self::Exited((code & 0xff) as u8)
    }

    pub fn wait4_status(self) -> u32 {
        match self {
            Self::Exited(code) => (code as u32) << 8,
            Self::Signaled(sig) => (sig as u32) & 0x7f,
        }
    }

    pub fn waitid_code(self) -> u32 {
        match self {
            Self::Exited(_) => 1,
            Self::Signaled(_) => 2,
        }
    }

    pub fn waitid_status(self) -> u32 {
        match self {
            Self::Exited(code) | Self::Signaled(code) => code as u32,
        }
    }
}

