//! Scheduler: per-hart fair run queues plus hart-local current-task state.
//!
//! All scheduler operations run with interrupts disabled on the current hart.
//! Runnable fair-task state is maintained in each hart-local scheduler state.
//!
//! # Locking discipline
//!
//! HartLocalState caches all data needed by the trap fast path
//! (user_token, trap_cx_ppn, is_user). This means the trap handler
//! avoids touching THREAD_TABLE or Thread locks unless it actually
//! needs to reschedule. Scheduler paths also avoid holding a hart-local
//! run-queue lock while taking THREAD_TABLE or Thread locks, so spawn/wake
//! and local schedule/yield/block paths cannot deadlock each other.

mod class;
mod fair;
pub mod futex;
mod idle;
pub mod pi;
pub mod robust;
mod rt;

use crate::sync::IrqSafeSpinlock;
use alloc::sync::Arc;
pub use class::{SchedClass, SchedPolicy};
use core::sync::atomic::{AtomicUsize, Ordering};

use crate::arch::{__switch, ThreadContext};
use crate::process::{self, Thread, ThreadState, Tid};
use crate::util::SpinMutex;
pub(crate) use idle::idle_spin;

use fair::{FairSchedClass, RunnableCursor};
use idle::IdleSchedClass;
use rt::RtSchedClass;

enum WakeAction {
    None,
    PendingOnly,
    Enqueue,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum SameThreadPickAction {
    FastReturn,
    CleanupBlocked,
    CleanupZombie,
    Retry,
}

fn apply_wake_transition(state: &mut ThreadState, wake_pending: &mut bool) -> WakeAction {
    match *state {
        ThreadState::Blocked => {
            *state = ThreadState::Ready;
            WakeAction::Enqueue
        }
        ThreadState::Running => {
            *wake_pending = true;
            WakeAction::PendingOnly
        }
        ThreadState::Ready | ThreadState::Exited | ThreadState::Zombie => WakeAction::None,
    }
}

fn same_thread_pick_action(state: ThreadState, policy: SchedPolicy) -> SameThreadPickAction {
    let queued_policy = matches!(
        policy,
        SchedPolicy::Fair | SchedPolicy::Fifo | SchedPolicy::RoundRobin
    );
    match state {
        ThreadState::Running | ThreadState::Ready => SameThreadPickAction::FastReturn,
        ThreadState::Blocked if queued_policy => SameThreadPickAction::CleanupBlocked,
        ThreadState::Zombie if queued_policy => SameThreadPickAction::CleanupZombie,
        ThreadState::Blocked | ThreadState::Zombie | ThreadState::Exited => {
            SameThreadPickAction::Retry
        }
    }
}

