            total_frames: 0,
            free_frames: 0,
            reserved_ranges: [(0, 0); MAX_RESERVED],
            reserved_count: 0,
        }
    }

    fn reset(&mut self) {
        self.bitmap.fill(0);
        self.regions = [Region::empty(); MAX_REGIONS];
        self.region_count = 0;
        self.total_frames = 0;
        self.free_frames = 0;
        self.reserved_ranges = [(0, 0); MAX_RESERVED];
        self.reserved_count = 0;
    }

    fn init_from_regions(
        &mut self,
        regions: &[MemoryRegion],
        reserved: &[(u64, u64)],
    ) -> (usize, usize) {
        self.reset();

        let mut usable = [Region::empty(); MAX_REGIONS];
        let (usable_count, skipped_regions) = collect_usable_regions(regions, &mut usable);
        if usable_count == 0 {
            return (skipped_regions, 0);
        }

        let mut next_bitmap_bit = 0usize;
        let mut skipped_frames = 0usize;
        for region in usable.iter_mut().take(usable_count) {
            let frame_count = ((region.end_addr - region.base_addr) / PAGE_SIZE as u64) as usize;
            if frame_count == 0 {
                continue;
            }
            if next_bitmap_bit + frame_count > MAX_TRACKED_FRAMES {
                skipped_frames += frame_count;
                break;
            }

            region.bitmap_offset = next_bitmap_bit;
            region.frame_count = frame_count;
            region.free_count = 0;
            self.regions[self.region_count] = *region;
            self.region_count += 1;
            self.total_frames += frame_count;
            next_bitmap_bit += frame_count;
        }

        for idx in 0..self.region_count {
            self.mark_region_free(idx);
        }

        for &(start, end) in reserved {
            self.mark_range_allocated(start, end);
