    fn find_region(&self, addr: u64) -> Option<usize> {
        (0..self.region_count).find(|&idx| self.regions[idx].contains(addr))
    }

    fn set_region_bit(&mut self, region_idx: usize, frame_idx: usize, free: bool) {
        let region = &mut self.regions[region_idx];
        let bit_idx = region.bitmap_offset + frame_idx;
        let byte_idx = bit_idx / 8;
        let mask = 1u8 << (bit_idx % 8);
        let was_free = self.bitmap[byte_idx] & mask != 0;

        if free && !was_free {
            self.bitmap[byte_idx] |= mask;
            region.free_count += 1;
            self.free_frames += 1;
        } else if !free && was_free {
            self.bitmap[byte_idx] &= !mask;
