//! Buddy allocator for kernel heap.
//!
//! Manages a contiguous heap region obtained from the frame allocator.
//! Power-of-2 block sizes from 32 bytes (order 0) to 262144 bytes (order 13).
//! Free lists per order; splits on alloc, merges on free.

use core::ptr;

/// Minimum allocation size (order 0).
pub const MIN_BLOCK: usize = 32;
/// Maximum allocation size (order MAX_ORDER).
pub const MAX_BLOCK: usize = 256 * 1024;
/// Number of orders: log2(262144/32) + 1 = 14 (orders 0..=13).
pub const ORDER_COUNT: usize = 14;

/// Compute the block size for a given order.
const fn block_size(order: usize) -> usize {
    MIN_BLOCK << order
}

/// Find the minimum order whose block size >= `size`.
fn size_to_order(size: usize) -> Option<usize> {
    for order in 0..ORDER_COUNT {
        if block_size(order) >= size {
            return Some(order);
        }
    }
    None
}

/// A free-list node embedded at the start of each free block.
struct FreeNode {
    next: *mut FreeNode,
}

/// Buddy allocator managing a contiguous heap region.
pub struct BuddyAllocator {
    /// Base address of the managed heap region.
    base: usize,
    /// Total size of the managed heap region (multiple of MAX_BLOCK).
    size: usize,
    /// Free list heads, one per order.
    free_lists: [*mut FreeNode; ORDER_COUNT],
}

impl BuddyAllocator {
    /// Create an uninitialized buddy allocator.
    pub const fn new() -> Self {
        Self {
            base: 0,
            size: 0,
            free_lists: [ptr::null_mut(); ORDER_COUNT],
        }
    }

    /// Initialize the buddy allocator over a contiguous region.
    ///
    /// `base` must be aligned to MAX_BLOCK. `size` must be a multiple of MAX_BLOCK.
    /// The region must be valid memory (identity-mapped physical frames).
    pub fn init(&mut self, base: usize, size: usize) {
        assert!(base % MAX_BLOCK == 0, "buddy base not aligned");
        assert!(size % MAX_BLOCK == 0, "buddy size not aligned");
        assert!(size > 0, "buddy size is zero");

        self.base = base;
        self.size = size;

        // Clear free lists.
        for list in &mut self.free_lists {
            *list = ptr::null_mut();
        }

        // Insert all max-order blocks into the highest-order free list.
        let max_order = ORDER_COUNT - 1;
        let num_blocks = size / MAX_BLOCK;
        for i in (0..num_blocks).rev() {
            let addr = base + i * MAX_BLOCK;
            self.list_push(max_order, addr);
        }
    }

    /// Allocate a block of at least `size` bytes. Returns the address or None.
    pub fn alloc(&mut self, size: usize) -> Option<usize> {
        let order = size_to_order(size)?;
        self.alloc_order(order)
    }

    /// Returns true if `addr` falls within the managed heap region.
    pub fn owns(&self, addr: usize) -> bool {
        addr >= self.base && addr < self.base + self.size
    }

    /// Free a block at `addr` with the given allocation `size`.
    ///
    /// The caller must provide the same size that was used for allocation.
    pub fn free(&mut self, addr: usize, size: usize) {
        let order = match size_to_order(size) {
            Some(o) => o,
            None => return,
        };
        if !self.valid_free_node(order, addr) {
            return;
        }
        self.free_order(addr, order);
    }

    fn alloc_order(&mut self, order: usize) -> Option<usize> {
        // Find the smallest available order >= requested.
        for current in order..ORDER_COUNT {
            if !self.free_lists[current].is_null() {
                if let Some(addr) = self.list_pop(current) {
                    // Split larger blocks down to the requested order.
                    for split in (order..current).rev() {
                        // Put the upper buddy on the free list.
                        let buddy = addr + block_size(split);
                        self.list_push(split, buddy);
                    }
                    return Some(addr);
                }
            }
        }
        None
    }

    fn free_order(&mut self, addr: usize, order: usize) {
        let mut addr = addr;
        let mut ord = order;

        if self.list_contains_covering(ord, addr) {
            return;
        }

        // Try to merge with buddy up to max order.
        while ord < ORDER_COUNT - 1 {
            let buddy = self.buddy_addr(addr, ord);
            if !self.list_remove(ord, buddy) {
                break;
            }
            // Merge: take the lower address as the new block.
            addr = addr.min(buddy);
            ord += 1;
        }

        self.list_push(ord, addr);
    }

    /// Compute the buddy address for a block at `addr` of given `order`.
    fn buddy_addr(&self, addr: usize, order: usize) -> usize {
        self.base + ((addr - self.base) ^ block_size(order))
    }

    /// Push an address onto the free list for `order`.
    fn list_push(&mut self, order: usize, addr: usize) {
        if !self.valid_free_node(order, addr) || self.list_contains(order, addr) {
            return;
        }
        let node = addr as *mut FreeNode;
        unsafe {
            (*node).next = self.free_lists[order];
        }
        self.free_lists[order] = node;
    }

    /// Pop the first address from the free list for `order`.
    fn list_pop(&mut self, order: usize) -> Option<usize> {
        let node = self.free_lists[order];
        if node.is_null() {
            return None;
        }
        if !self.valid_free_node(order, node as usize) {
            self.free_lists[order] = ptr::null_mut();
            return None;
        }
        unsafe {
            self.free_lists[order] = (*node).next;
        }
        Some(node as usize)
    }

    /// Remove a specific address from the free list for `order`.
    /// Returns true if found and removed.
    fn list_remove(&mut self, order: usize, addr: usize) -> bool {
        let target = addr as *mut FreeNode;
        let mut prev: *mut *mut FreeNode = &mut self.free_lists[order];
        let mut seen = 0usize;
        let max_seen = self.max_nodes(order);
        unsafe {
            while !(*prev).is_null() {
                if seen >= max_seen || !self.valid_free_node(order, *prev as usize) {
                    *prev = ptr::null_mut();
                    return false;
                }
                if *prev == target {
                    *prev = (*target).next;
                    return true;
                }
                prev = &mut (**prev).next;
                seen += 1;
            }
        }
        false
    }

    fn list_contains(&self, order: usize, addr: usize) -> bool {
        if !self.valid_free_node(order, addr) {
            return false;
        }
        let target = addr as *mut FreeNode;
        let mut node = self.free_lists[order];
        let mut seen = 0usize;
        let max_seen = self.max_nodes(order);
        unsafe {
            while !node.is_null() && seen < max_seen {
                if !self.valid_free_node(order, node as usize) {
                    return false;
                }
                if node == target {
                    return true;
                }
                node = (*node).next;
                seen += 1;
            }
        }
        false
    }

    fn list_contains_covering(&self, order: usize, addr: usize) -> bool {
        for current in order..ORDER_COUNT {
            let block = block_size(current);
            let covering_addr = self.base + ((addr - self.base) / block) * block;
            if self.list_contains(current, covering_addr) {
                return true;
            }
        }
        false
    }

    fn valid_free_node(&self, order: usize, addr: usize) -> bool {
        self.owns(addr) && (addr - self.base) % block_size(order) == 0
    }

    fn max_nodes(&self, order: usize) -> usize {
        let block = block_size(order);
        if block == 0 { 0 } else { self.size / block }
    }
}

