//! Slab allocator for fixed-size small object caches.
//!
//! Pre-defined slab sizes: 32, 64, 128, 256, 512 bytes.
//! Each slab cache manages a linked list of slabs, where each slab is one
//! 4 KiB page subdivided into equal-sized objects.

use crate::mm::{PAGE_SIZE, alloc_frame};
use core::ptr;

/// Available slab size classes.
pub const SLAB_SIZES: [usize; 5] = [32, 64, 128, 256, 512];
/// Number of slab size classes.
pub const SLAB_CLASS_COUNT: usize = SLAB_SIZES.len();

/// Find the slab class index for a given size, or None if too large.
pub fn slab_class_for(size: usize) -> Option<usize> {
    for (i, &s) in SLAB_SIZES.iter().enumerate() {
        if s >= size {
            return Some(i);
        }
    }
    None
}

/// A free object node embedded at the start of each free slot.
struct FreeObj {
    next: *mut FreeObj,
}

/// Header at the start of each slab page, tracking the free list and metadata.
/// This lives in the first `obj_size` bytes of the page (consuming one object slot).
struct SlabHeader {
    /// Next slab page in this cache's list.
    next_slab: *mut SlabHeader,
    /// Free object list within this slab.
    free_list: *mut FreeObj,
    /// Number of currently allocated objects.
    in_use: usize,
    /// Total number of usable object slots (excluding the header slot).
    capacity: usize,
}

/// A single slab cache for one size class.
pub struct SlabCache {
    obj_size: usize,
    /// Linked list of slab pages.
    slabs: *mut SlabHeader,
}

impl SlabCache {
    pub const fn new(obj_size: usize) -> Self {
        Self {
            obj_size,
            slabs: ptr::null_mut(),
        }
    }

    /// Allocate one object from this cache.
    pub fn alloc(&mut self) -> Option<*mut u8> {
        if let Some(obj) = self.alloc_existing() {
            return Some(obj);
        }

        // No free slots — allocate a new slab page.
        let frame = alloc_frame()?;
        self.grow_from_page(frame as usize);
        self.alloc_existing()
    }

    /// Allocate one object from existing slab pages only.
    pub fn alloc_existing(&mut self) -> Option<*mut u8> {
        let mut slab = self.slabs;
        while !slab.is_null() {
            unsafe {
                if !(*slab).free_list.is_null() {
                    let obj = (*slab).free_list;
                    (*slab).free_list = (*obj).next;
                    (*slab).in_use += 1;
                    return Some(obj as *mut u8);
                }
                slab = (*slab).next_slab;
            }
        }
        None
    }

    /// Free an object back into its slab.
    pub fn free(&mut self, ptr: *mut u8) -> bool {
        let addr = ptr as usize;
        let page_base = addr & !(PAGE_SIZE - 1);

        // Find the slab this object belongs to.
        let mut slab = self.slabs;
        while !slab.is_null() {
            if slab as usize == page_base {
                if !self.valid_object_ptr(slab, addr) {
                    return false;
                }
                if self.free_list_contains(slab, ptr as *mut FreeObj) {
                    return false;
                }
                unsafe {
                    let obj = ptr as *mut FreeObj;
                    (*obj).next = (*slab).free_list;
                    (*slab).free_list = obj;
                    (*slab).in_use -= 1;

                    // If slab is completely empty, we could free the page.
                    // Keep it for now — simpler and avoids thrashing.
                }
                return true;
            }
            unsafe {
                slab = (*slab).next_slab;
            }
        }
        false
    }

    /// Check if a pointer belongs to a slab managed by this cache.
    pub fn owns(&self, ptr: *mut u8) -> bool {
        let addr = ptr as usize;
        let page_base = addr & !(PAGE_SIZE - 1);
        let mut slab = self.slabs;
        while !slab.is_null() {
            if slab as usize == page_base {
                return self.valid_object_ptr(slab, addr);
            }
            unsafe {
                slab = (*slab).next_slab;
            }
        }
        false
    }

    fn valid_object_ptr(&self, slab: *mut SlabHeader, addr: usize) -> bool {
        let page = slab as usize;
        let offset = addr.wrapping_sub(page);
        if offset < self.obj_size || offset >= PAGE_SIZE || offset % self.obj_size != 0 {
            return false;
        }
        unsafe {
            let slot = offset / self.obj_size;
            slot <= (*slab).capacity
        }
    }

    fn free_list_contains(&self, slab: *mut SlabHeader, target: *mut FreeObj) -> bool {
        let mut node = unsafe { (*slab).free_list };
        let mut seen = 0usize;
        let max_seen = unsafe { (*slab).capacity };
        while !node.is_null() && seen < max_seen {
            if node == target {
                return true;
            }
            if !self.valid_object_ptr(slab, node as usize) {
                return false;
            }
            node = unsafe { (*node).next };
            seen += 1;
        }
        false
    }

    /// Add a new slab page to this cache.
    pub fn grow_from_page(&mut self, page: usize) {
        // Zero the page.
        unsafe {
            ptr::write_bytes(page as *mut u8, 0, PAGE_SIZE);
        }

        let header = page as *mut SlabHeader;
        let obj_size = self.obj_size;

        // The header occupies the first obj_size bytes.
        // Remaining slots start at page + obj_size.
        let capacity = (PAGE_SIZE / obj_size) - 1;

        unsafe {
            (*header).next_slab = self.slabs;
            (*header).in_use = 0;
            (*header).capacity = capacity;

            // Build free list for slots [1..capacity+1).
            (*header).free_list = ptr::null_mut();
            for i in (1..=capacity).rev() {
                let slot = (page + i * obj_size) as *mut FreeObj;
                (*slot).next = (*header).free_list;
                (*header).free_list = slot;
            }
        }

        self.slabs = header;
    }
}

/// The slab allocator: an array of caches, one per size class.
pub struct SlabAllocator {
    caches: [SlabCache; SLAB_CLASS_COUNT],
}

impl SlabAllocator {
    pub const fn new() -> Self {
        Self {
            caches: [
                SlabCache::new(SLAB_SIZES[0]),
                SlabCache::new(SLAB_SIZES[1]),
                SlabCache::new(SLAB_SIZES[2]),
                SlabCache::new(SLAB_SIZES[3]),
                SlabCache::new(SLAB_SIZES[4]),
            ],
        }
    }

    /// Allocate an object of at least `size` bytes.
    pub fn alloc(&mut self, size: usize) -> Option<*mut u8> {
        let idx = slab_class_for(size)?;
        self.caches[idx].alloc()
    }

    /// Allocate from existing slab pages only.
    pub fn alloc_existing(&mut self, size: usize) -> Option<*mut u8> {
        let idx = slab_class_for(size)?;
        self.caches[idx].alloc_existing()
    }

    /// Add a slab page for the size class that serves `size`.
    pub fn grow_from_page(&mut self, size: usize, page: usize) -> Option<()> {
        let idx = slab_class_for(size)?;
        self.caches[idx].grow_from_page(page);
        Some(())
    }

    /// Free an object. Returns true if the object belonged to a slab cache.
    pub fn free(&mut self, ptr: *mut u8) -> bool {
        for cache in &mut self.caches {
            if cache.owns(ptr) {
                return cache.free(ptr);
            }
        }
        false
    }

    /// Returns true if `ptr` belongs to any slab cache managed by this allocator.
    pub fn owns(&self, ptr: *mut u8) -> bool {
        self.caches.iter().any(|cache| cache.owns(ptr))
    }
}

