    publish_root(&node);
    *root = Some(node);
    drop(root);
    if !INIT_LOGGED.swap(true, Ordering::AcqRel) {
        if replaced {
            info!("fs: root replaced with disk-backed filesystem");
        } else {
            info!("fs: root set to disk-backed filesystem");
        }
    }
