pub fn lookup(path: &str) -> Result<NodeRef> {
    if path == "/" {
        return root_node();
    }

    // If path lives under a registered mount point, redirect to the
    // mounted filesystem's root and resolve the remainder there.
    if let Some((mounted_root, remainder)) = mount::find_mount(path) {
        if remainder == "/" || remainder.is_empty() {
            return Ok(mounted_root);
        }
        let mut node = mounted_root;
        for component in normalize_path(&remainder)? {
            node = node.lookup(component)?;
        }
        return Ok(node);
    }

    let mut node = root_node()?;
    for component in normalize_path(path)? {
        node = node.lookup(component)?;
    }
    Ok(node)
