    Handler(usize),
}

/// Per-thread signal state (pending/blocked masks only).
/// Signal dispositions are process-wide and stored in Process.
pub struct SignalState {
    /// Bitmask of pending signals.
    pub pending: u32,
    /// Bitmask of blocked signals.
    pub blocked: u32,
}

impl SignalState {
    pub fn new() -> Self {
        Self {
            pending: 0,
            blocked: 0,
        }
    }

    /// Check whether signal `sig` is blocked (1..31).
    pub fn is_blocked(&self, sig: usize) -> bool {
        if sig == 0 || sig >= SIG_N {
            return true;
        }
        self.blocked & (1 << (sig - 1)) != 0
    }

    /// Mask-in new blocked signals per `how`.
    /// how: SIG_BLOCK=0, SIG_UNBLOCK=1, SIG_SETMASK=2.
    pub fn sigprocmask(&mut self, how: usize, set: u32) {
        match how {
            0 /* SIG_BLOCK */ => self.blocked |= set,
            1 /* SIG_UNBLOCK */ => self.blocked &= !set,
            2 /* SIG_SETMASK */ => self.blocked = set,
            _ => {}
        }
        // SIGKILL and SIGSTOP are always unblockable.
        self.blocked &= !((1 << (SIGKILL - 1)) | (1 << (SIGSTOP - 1)));
    }

    /// Send signal `sig` to this thread.
    pub fn send(&mut self, sig: usize) {
        if sig == 0 || sig >= SIG_N {
            return;
        }
        self.pending |= 1 << (sig - 1);
    }

    /// Get the next pending, unblocked signal, or 0 if none.
    pub fn next_pending_unblocked(&self) -> usize {
        let allowed = self.pending & !self.blocked;
        if allowed == 0 {
            return 0;
        }
        allowed.trailing_zeros() as usize + 1
    }

    /// Clear a pending signal.
    pub fn clear_pending(&mut self, sig: usize) {
        if sig >= 1 && sig < SIG_N {
            self.pending &= !(1 << (sig - 1));
        }
    }
}

/// Magic value written at the start of a SigFrame so sigreturn can
/// validate that the stack really holds a saved context.
pub const SIGFRAME_MAGIC: u64 = 0x5349_4746_5241_4D45; // "SIGFRAME"

/// Signal frame saved on the user stack before entering a signal handler.
/// sigreturn reads this frame and restores the full user context.
///
/// Must be 16-byte aligned on the stack. The frame is placed below the
/// handler's stack frame so it survives handler execution.
#[repr(C)]
pub struct SigFrame {
    /// Magic cookie for validation.
    pub magic: u64,
    /// Signal number that triggered this frame.
    pub sig: u64,
    /// Saved general-purpose registers (x0..x31 / r0..r31).
    pub regs: [u64; 32],
    /// Saved program counter (sepc on RISC-V, era on LoongArch).
    pub pc: u64,
    /// Saved status register (sstatus on RISC-V, prmd on LoongArch).
    pub status: u64,
    /// Saved blocked signal mask (restored on sigreturn).
    pub blocked: u32,
}

/// Whether signal delivery is globally enabled.
static SIGNALS_READY: AtomicBool = AtomicBool::new(false);

pub fn signals_ready() -> bool {
    SIGNALS_READY.load(Ordering::Acquire)
}

pub fn set_signals_ready() {
    SIGNALS_READY.store(true, Ordering::Release);
}

