pub fn handle_illegal_instruction(frame: &mut TrapFrame) {
    let (fault_pc, cause, stval) = frame.fault_info();

    if crate::sched::current_is_user() {
        error!(
            "illegal instruction in user mode: cause={:#x}, pc={:#x}, stval={:#x} -- killing process",
            cause, fault_pc, stval
        );
        crate::process::exit_current(-2);
    } else {
        panic!(
            "illegal instruction in kernel mode: cause={:#x}, pc={:#x}, stval={:#x}",
            cause, fault_pc, stval
        );
    }
}

