    let (fault_pc, cause, stval) = frame.fault_info();

    if crate::sched::current_is_user() {
        error!(
            "unknown trap in user mode: cause={:#x}, pc={:#x}, stval={:#x} -- killing process",
            cause, fault_pc, stval
        );
        crate::process::exit_current(-3);
    } else {
        panic!(
            "unknown trap in kernel mode: cause={:#x}, pc={:#x}, stval={:#x}",
            cause, fault_pc, stval
        );
    }
}

