fn elf_flags_to_perm(flags: u32) -> MapPermission {
    let mut perm = MapPermission::USER;
    // Writable ELF segments are expected to be readable by user code.  This is
    // especially visible on LoongArch, where a missing READ bit becomes NR.
    if flags & (PF_R | PF_W) != 0 {
        perm = perm | MapPermission::READ;
    }
    if flags & PF_W != 0 {
        perm = perm | MapPermission::WRITE;
    }
    if flags & PF_X != 0 {
        perm = perm | MapPermission::EXECUTE;
    }
    perm
}

