    BOOT_HART_ID.load(Ordering::Relaxed) as usize
}

/// Returns the DTB pointer saved during init_boot_info, if any.
pub fn current_dtb_ptr() -> Option<u64> {
    let ptr = DTB_PTR.load(Ordering::Acquire);
    if ptr == 0 { None } else { Some(ptr) }
}

static INITRD_START: AtomicU64 = AtomicU64::new(0);
static INITRD_SIZE: AtomicU64 = AtomicU64::new(0);

/// Returns the initramfs data slice, if one was provided by the bootloader.
/// The physical pages must already be identity-mapped (done during mm::init).
pub fn initrd() -> Option<&'static [u8]> {
    let start = INITRD_START.load(Ordering::Acquire) as usize;
    let size = INITRD_SIZE.load(Ordering::Acquire) as usize;
    if size > 0 {
        Some(unsafe { core::slice::from_raw_parts(start as *const u8, size) })
    } else {
        None
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
