pub enum MemoryKind {
    Available = 0,
    Reserved = 1,
    AcpiReclaim = 2,
    AcpiNvs = 3,
    Mmio = 4,
    BootInfoReserved = 5,
}

#[derive(Debug, Clone, Copy)]
#[repr(C)]
pub struct MemoryRegion {
    pub base: u64,
    pub size: u64,
    pub kind: MemoryKind,
}

#[repr(C)]
pub struct BootInfo {
    pub magic: u64,
    pub version: u32,
    pub boot_hart_id: u64,
    pub dtb_ptr: u64,
    pub dtb_size: usize,
    pub initrd_start: u64,
    pub initrd_size: u64,
    pub acpi_rsdp: u64,
    pub acpi_ptr: u64,
    pub acpi_size: u32,
    pub acpi_blob_ptr: u64,
    pub acpi_blob_size: usize,
    pub num_memory_regions: u32,
    // MemoryRegion array follows immediately after BootInfo
}

impl BootInfo {
    /// Returns the MemoryRegion slice trailing this BootInfo.
    pub fn memory_regions(&self) -> &[MemoryRegion] {
        let regions_offset = size_of::<BootInfo>().next_multiple_of(align_of::<MemoryRegion>());
        let regions_ptr = (self as *const Self)
            .cast::<u8>()
            .wrapping_add(regions_offset) as *const MemoryRegion;
        unsafe { core::slice::from_raw_parts(regions_ptr, self.num_memory_regions as usize) }
    }

    pub fn acpi_blob_ptr(&self) -> u64 {
        self.acpi_blob_ptr
    }
    pub fn acpi_blob_size(&self) -> usize {
        self.acpi_blob_size
    }
    pub fn acpi_rsdp(&self) -> Option<u64> {
        if self.acpi_rsdp != 0 {
            Some(self.acpi_rsdp)
        } else {
            None
        }
    }

