static IRQ_REVERSE_MAP: SyncUnsafeCell<[[u32; MAX_IRQS_PER_CHIP]; MAX_CHIPS]> =
    SyncUnsafeCell::new([[INVALID_IRQ; MAX_IRQS_PER_CHIP]; MAX_CHIPS]);

fn irq_desc_table() -> &'static [IrqDesc; MAX_IRQS] {
    unsafe { &*IRQ_DESC_TABLE.get() }
}

fn irq_desc_table_mut() -> &'static mut [IrqDesc; MAX_IRQS] {
    unsafe { &mut *IRQ_DESC_TABLE.get() }
}

fn reverse_irq_lookup(chip: &dyn IrqChip, hwirq: u32) -> Option<u32> {
    let chip_id = chip.chip_id() as usize;
    let hw = hwirq as usize;
    if chip_id >= MAX_CHIPS || hw >= MAX_IRQS_PER_CHIP {
        return None;
    }
    let map = unsafe { &*IRQ_REVERSE_MAP.get() };
    match map[chip_id][hw] {
        INVALID_IRQ => None,
        irq => Some(irq),
    }
}

fn set_reverse_map(chip_id: u8, hwirq: u32, linux_irq: u32) {
    let map = unsafe { &mut *IRQ_REVERSE_MAP.get() };
    map[chip_id as usize][hwirq as usize] = linux_irq;
}

// ---------------------------------------------------------------------------
// IrqDomain
// ---------------------------------------------------------------------------

pub struct IrqDomain {
    base: u32,
    count: u32,
    name: &'static str,
}

impl IrqDomain {
    pub fn new_linear(base: u32, count: u32, name: &'static str) -> Result<Self, IrqError> {
        if base as usize + count as usize > MAX_IRQS {
            return Err(IrqError::InvalidIrq);
        }
        Ok(Self { base, count, name })
    }

    pub fn map_hwirq(
        &self,
        hwirq: u32,
        chip: &'static dyn IrqChip,
        handler: IrqHandler,
        name: &'static str,
    ) -> Result<u32, IrqError> {
        if hwirq >= self.count {
            return Err(IrqError::InvalidHwirq);
        }
        if chip.chip_id() as usize >= MAX_CHIPS
            || hwirq >= chip.irq_count()
            || hwirq as usize >= MAX_IRQS_PER_CHIP
        {
            return Err(IrqError::InvalidHwirq);
        }
        let irq = self.base + hwirq;
        let table = irq_desc_table_mut();
        let desc = &mut table[irq as usize];
        if desc.handler.is_some() {
            return Err(IrqError::AlreadyRegistered);
        }
        desc.handler = Some(handler);
        desc.name = Some(name);
        desc.chip = Some(chip);
        desc.hwirq = hwirq;
        set_reverse_map(chip.chip_id(), hwirq, irq);
        Ok(irq)
    }
}

// ---------------------------------------------------------------------------
// Errors
// ---------------------------------------------------------------------------

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum IrqError {
    AlreadyRegistered,
    InvalidHwirq,
    InvalidIrq,
    Unsupported,
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/// IRQ registration is done exclusively through IrqDomain::map_hwirq,
/// which fills all descriptor fields (handler, name, chip, hwirq)
/// and populates the reverse map. There is no standalone request_irq.

pub fn free_irq(irq: u32) -> Result<(), IrqError> {
    let table = irq_desc_table_mut();
    let desc = table.get_mut(irq as usize).ok_or(IrqError::InvalidIrq)?;
    desc.handler = None;
    desc.name = None;
    Ok(())
}

pub fn enable_irq(irq: u32) {
    let desc = match irq_desc_table().get(irq as usize) {
        Some(d) if d.chip.is_some() => d,
        _ => return,
    };
    let _ = desc.chip.unwrap().unmask(desc.hwirq);
}

pub fn disable_irq(irq: u32) {
    let desc = match irq_desc_table().get(irq as usize) {
        Some(d) if d.chip.is_some() => d,
        _ => return,
    };
    let _ = desc.chip.unwrap().mask(desc.hwirq);
}

pub fn irq_set_affinity(irq: u32, mask: &HartMask) -> Result<(), IrqError> {
    let table = irq_desc_table_mut();
    let desc = table.get_mut(irq as usize).ok_or(IrqError::InvalidIrq)?;
    desc.affinity = *mask;
    if let Some(chip) = desc.chip {
        chip.set_affinity(desc.hwirq, mask);
    }
    Ok(())
}

