/// Platform parent chip, set by arch init (PLIC or EIOINTC).
static mut PARENT_CHIP: Option<&'static dyn IrqChip> = None;

/// Set the parent chip during platform init. Called once, before IRQs are enabled.
pub fn set_parent_chip(chip: &'static dyn IrqChip) {
    unsafe {
        PARENT_CHIP = Some(chip);
    }
}

/// Handle an external interrupt on the current hart. Called from trap dispatch.
pub fn handle_external(_frame: &mut TrapFrame) {
    let chip = match unsafe { PARENT_CHIP } {
        Some(c) => c,
        None => return,
    };

    let Some(hwirq) = chip.claim() else {
        return;
    };

    let Some(irq) = reverse_irq_lookup(chip, hwirq) else {
        chip.eoi(hwirq);
        return;
    };

    let Some(desc) = irq_desc_table().get(irq as usize) else {
        chip.eoi(hwirq);
        return;
    };
    let desc_chip = desc.chip.unwrap_or(chip);
    desc.count.fetch_add(1, Ordering::Relaxed);

    if let Some(handler) = desc.handler {
        handler();
    }

    desc_chip.eoi(desc.hwirq);
}

