// ---------------------------------------------------------------------------
// HartMask — compact bitmask of hart IDs
// ---------------------------------------------------------------------------

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct HartMask {
    bits: u64,
}

impl HartMask {
    pub const fn empty() -> Self {
        Self { bits: 0 }
    }

    pub fn insert(&mut self, hart_id: usize) -> Result<(), &'static str> {
        if hart_id >= MAX_HARTS {
            return Err("hart_id out of range for HartMask");
        }
        self.bits |= 1 << hart_id;
        Ok(())
    }

    pub fn remove(&mut self, hart_id: usize) {
        if hart_id < MAX_HARTS {
            self.bits &= !(1 << hart_id);
        }
    }

    pub fn contains(&self, hart_id: usize) -> bool {
        if hart_id >= MAX_HARTS {
            return false;
        }
        (self.bits >> hart_id) & 1 != 0
    }

    pub fn bits(&self) -> u64 {
        self.bits
    }
}

pub fn mask_as_slice(mask: &HartMask) -> impl Iterator<Item = usize> + Clone {
    let bits = mask.bits();
    (0..MAX_HARTS).filter(move |&h| (bits >> h) & 1 != 0)
}

// ---------------------------------------------------------------------------
// HartSet — ordered set of hart IDs (for iteration)
// ---------------------------------------------------------------------------

#[derive(Clone)]
pub struct HartSet {
    harts: [usize; MAX_HARTS],
    len: usize,
}

impl HartSet {
    pub fn from_iter(iter: impl Iterator<Item = usize>) -> Self {
        let mut set = Self {
            harts: [0; MAX_HARTS],
            len: 0,
        };
        for hart_id in iter {
            if set.len < MAX_HARTS {
                set.harts[set.len] = hart_id;
                set.len += 1;
            }
        }
        set
    }

    pub fn contains(&self, hart_id: usize) -> bool {
        self.harts[..self.len].contains(&hart_id)
    }

    pub fn as_slice(&self) -> &[usize] {
        &self.harts[..self.len]
    }

    pub fn is_empty(&self) -> bool {
        self.len == 0
    }
}

