        self.mark_offline(hart_id);
        Ok(())
    }

    pub fn teardown_complete(&mut self, hart_id: usize) {
        let info = &mut self.harts[hart_id];
        debug_assert!(info.state == HartState::Teardown);
        info.state = HartState::Offline;
    }

    pub fn hart_state(&self, hart_id: usize) -> HartState {
        self.harts[hart_id].state
    }
