//! Clock subsystem (時計 — "clock").
//!
//! ## Architecture
//! Three-layer design isolating hardware access from timekeeping:
//!
//! - **Clocksource** — Global read-only hardware counter. All harts share one.
//! - **Clockevent** — Per-hart programmable timer interrupt. Each hart arms
//!   its own comparator.
//! - **Timekeeper** — Monotonic nanosecond clock. One designated hart
//!   advances it; all harts read it lock-free.
//!
//! ## Initialization order
//! `tokei::init()` must be called **after** `trap::init_trapping()` and
//! **after** `mm::init()`, but before enabling global interrupts.
//!
//! ## Tick model
//! Uses a oneshot timer re-armed on each interrupt. Current interval is
//! 10 ms (100 Hz). This provides the same behavior as a periodic timer
//! while keeping the NO_HZ upgrade path open.

pub mod clockevent;
pub mod clocksource;
mod timekeeper;
pub mod timer_list;

use core::sync::atomic::{AtomicUsize, Ordering};

use crate::arch::shared::sync::SyncUnsafeCell;
use clockevent::Clockevent;

use crate::arch::TICK_PERIOD_MS;

/// Per-hart clockevent instances.
static CLOCKEVENTS: [SyncUnsafeCell<Option<Clockevent>>; crate::smp::MAX_HARTS] =
    [const { SyncUnsafeCell::new(None) }; crate::smp::MAX_HARTS];

fn clockevent_for(hart_id: usize) -> &'static Clockevent {
    assert!(hart_id < crate::smp::MAX_HARTS);
    unsafe {
        (*CLOCKEVENTS[hart_id].get())
            .as_ref()
            .expect("clockevent_for: hart not initialized")
    }
}

/// Per-hart software timer lists.
static TIMER_LISTS: [SyncUnsafeCell<Option<timer_list::TimerList>>; crate::smp::MAX_HARTS] =
    [const { SyncUnsafeCell::new(None) }; crate::smp::MAX_HARTS];

fn timer_list_for(hart_id: usize) -> &'static mut timer_list::TimerList {
    assert!(hart_id < crate::smp::MAX_HARTS);
    unsafe {
        (*TIMER_LISTS[hart_id].get())
            .as_mut()
            .expect("timer_list_for: hart not initialized")
    }
}

/// The hart responsible for advancing global time.
/// The hart responsible for advancing global monotonic time.
/// Set once during `tokei::init` on the boot hart.
static TIMEKEEPER_HART_ID: AtomicUsize = AtomicUsize::new(usize::MAX);

/// Initializes the clock subsystem.
///
/// # Safety
/// Must be called exactly once per boot per hart, after `trap::init_trapping()`.
pub unsafe fn init(hart_id: usize, timebase_freq_hz: Option<u64>) {
    use crate::arch;

    let freq = arch::timer::timebase_freq(timebase_freq_hz);
    let read_fn = arch::timer::clocksource_read_fn();

    let boot_hart = crate::boot::boot_hart_id();

    // 1. Initialize the global clocksource (boot hart only)
    if hart_id == boot_hart {
        clocksource::Clocksource::init(freq, read_fn);
    }

    // 2. Create per-hart clockevent
    let ce = Clockevent::new(
        arch::timer::set_timer,
        arch::timer::enable_timer_interrupt,
        arch::timer::disable_timer_interrupt,
    );

    // 3. Initialize timekeeper with current cycle count (boot hart only)
    if hart_id == boot_hart {
        let cs = clocksource::get();
        let cycles = cs.read();
        timekeeper::init(cycles);
        TIMEKEEPER_HART_ID.store(boot_hart, Ordering::Release);
    }

    // 4. Initialize per-hart timer list.
    unsafe {
        *TIMER_LISTS[hart_id].get() = Some(timer_list::TimerList::new());
    }

    // 5. Store clockevent. It is enabled and armed only after scheduler and
    //    init setup completes.
    unsafe {
        *CLOCKEVENTS[hart_id].get() = Some(ce);
    }

    info!("tokei: hart={}, freq={} Hz", hart_id, freq);
}

/// Enable and arm the per-hart clockevent after scheduler state is ready.
pub fn start_tick(hart_id: usize) {
    let ce_ref = clockevent_for(hart_id);
    unsafe {
        ce_ref.enable();
    }

    program_next_event(hart_id);
}

/// Timer interrupt handler.
///
/// Called from the architecture trap dispatch when a supervisor timer
/// interrupt fires. Runs with interrupts disabled.
///
/// ## Tick flow
/// 1. Read current hardware cycles
/// 2. Re-arm the clockevent for the next tick (TICK_PERIOD_MS from now)
/// 3. If this hart is the timekeeper hart: advance global monotonic time
pub fn handle_timer(hart_id: usize) {
    let cs = clocksource::get();
    let now = cs.read();

    // Advance global time if this hart is the timekeeper
    if hart_id == TIMEKEEPER_HART_ID.load(Ordering::Acquire) {
        timekeeper::do_timer(now);
    }

    // Pop expired software timers and wake their threads.
    let expired = timer_list_for(hart_id).pop_expired(now);
    for tid in expired {
        crate::sched::wake_up(tid);
    }

    program_next_event(hart_id);
}

/// Returns the current monotonic time in nanoseconds since boot.
///
/// Lock-free. Safe to call from any context (interrupt handler, syscall).
pub fn current_time_ns() -> u64 {
    timekeeper::current_time_ns()
}

/// Refresh the monotonic timekeeper from the hardware clocksource.
///
/// This is used by polling sleep paths that do not return through a timer
/// interrupt before userspace reads the clock again.
pub fn refresh_timekeeper() {
    let hart_id = crate::arch::current_hart_id();
    if hart_id == TIMEKEEPER_HART_ID.load(Ordering::Acquire) {
        let now = clocksource::get().read();
        timekeeper::do_timer(now);
    }
}

fn clockevent_deadline_for_ns(deadline_ns: u64) -> u64 {
    let now_ns = current_time_ns();
    let remaining_ns = deadline_ns.saturating_sub(now_ns);
    let cs = clocksource::get();
    cs.read().wrapping_add(cs.ns_to_ticks(remaining_ns))
}

fn clockevent_deadline_after_ns(duration_ns: u64) -> u64 {
    let cs = clocksource::get();
    cs.read().wrapping_add(cs.ns_to_ticks(duration_ns))
}

fn tick_deadline_ticks() -> u64 {
    let cs = clocksource::get();
    let tick_interval_ticks = cs.ns_to_ticks(TICK_PERIOD_MS * 1_000_000);
    cs.read().wrapping_add(tick_interval_ticks)
}

fn program_next_event(hart_id: usize) {
    let now = clocksource::get().read();
    let tick_deadline = tick_deadline_ticks();
    let next_deadline = timer_list_for(hart_id)
        .next_active_deadline_ticks()
        .map(|timer_deadline| core::cmp::min(tick_deadline, timer_deadline))
        .unwrap_or(tick_deadline);
    let next_deadline = if next_deadline <= now {
        now.saturating_add(1)
    } else {
        next_deadline
    };
    unsafe { clockevent_for(hart_id).set_timeout(next_deadline) };
}

/// Insert a software timer that wakes `tid` at `deadline_ns` (monotonic ns).
/// Returns the hart-local timer list that owns the entry, for cancellation.
pub fn insert_timer_with_token(deadline_ns: u64, tid: usize, token: u64) -> usize {
    let irq = crate::arch::arch_irq_save();
    let hart = crate::arch::current_hart_id();
    let deadline_ticks = clockevent_deadline_for_ns(deadline_ns);
    timer_list_for(hart).insert(deadline_ticks, tid, token);
    program_next_event(hart);
    crate::arch::arch_irq_restore(irq);
    hart
}

/// Insert a software timer that wakes `tid` after `duration_ns`.
/// Returns the hart-local timer list that owns the entry, for cancellation.
pub fn insert_timer_after_with_token(duration_ns: u64, tid: usize, token: u64) -> usize {
    let irq = crate::arch::arch_irq_save();
    let hart = crate::arch::current_hart_id();
    let deadline_ticks = clockevent_deadline_after_ns(duration_ns);
    timer_list_for(hart).insert(deadline_ticks, tid, token);
    program_next_event(hart);
    crate::arch::arch_irq_restore(irq);
    hart
}

/// Cancel the pending software timer for `(tid, token)` on the owning hart.
pub fn cancel_timer(hart_id: usize, tid: usize, token: u64) -> bool {
    if hart_id >= crate::smp::MAX_HARTS {
        return false;
    }

    let irq = crate::arch::arch_irq_save();
    let cancelled = timer_list_for(hart_id).cancel(tid, token);
    if cancelled && hart_id == crate::arch::current_hart_id() {
        program_next_event(hart_id);
    }
    crate::arch::arch_irq_restore(irq);
    cancelled
}

