// Saved interrupt-enable state. `Copy` token returned by `_irqsave`,
// required by `_irqrestore`.
#[derive(Clone, Copy)]
pub struct IrqState(pub(crate) bool);

impl IrqState {
    pub const fn new(was_enabled: bool) -> Self {
        Self(was_enabled)
    }

    pub const fn was_enabled(self) -> bool {
        self.0
    }
}

// ---------------------------------------------------------------------------
// RawSpinlock — ticket-based FIFO spinlock
// ---------------------------------------------------------------------------

pub struct RawSpinlock {
    ticket: AtomicU32,
    serving: AtomicU32,
}

impl RawSpinlock {
    pub const fn new() -> Self {
        Self {
            ticket: AtomicU32::new(0),
            serving: AtomicU32::new(0),
        }
    }

    /// Acquire the lock. Spins until our ticket is served.
    pub fn lock(&self) {
        let my_ticket = self.ticket.fetch_add(1, Ordering::Relaxed);
        while self.serving.load(Ordering::Acquire) != my_ticket {
            core::hint::spin_loop();
        }
    }

    /// Release the lock. Advances the serving counter.
    pub fn unlock(&self) {
        self.serving.fetch_add(1, Ordering::Release);
    }

    /// Try to acquire without spinning. Returns true on success.
    pub fn try_lock(&self) -> bool {
        let ticket = self.ticket.load(Ordering::Relaxed);
        let serving = self.serving.load(Ordering::Acquire);
        if ticket != serving {
            return false;
        }
        self.ticket
            .compare_exchange(ticket, ticket + 1, Ordering::Acquire, Ordering::Relaxed)
            .is_ok()
    }
}

// ---------------------------------------------------------------------------
// IRQ-safe lock/unlock
// ---------------------------------------------------------------------------

// Acquire `lock`, disabling interrupts on the local hart.
// Returns the previous interrupt state for later `spin_unlock_irqrestore`.
pub fn spin_lock_irqsave(lock: &RawSpinlock) -> IrqState {
    let state = crate::arch::arch_irq_save();
    lock.lock();
    state
}

// Release `lock`, restoring the interrupt state from the matching `_irqsave`.
pub fn spin_unlock_irqrestore(lock: &RawSpinlock, state: IrqState) {
    lock.unlock();
    crate::arch::arch_irq_restore(state);
}

// ---------------------------------------------------------------------------
// IrqSafeSpinlock<T> — lock wrapper with built-in IRQ disable
// ---------------------------------------------------------------------------

pub struct IrqSafeSpinlock<T> {
    lock: RawSpinlock,
    data: SyncUnsafeCell<T>,
}

impl<T> IrqSafeSpinlock<T> {
    pub const fn new(data: T) -> Self {
        Self {
            lock: RawSpinlock::new(),
            data: SyncUnsafeCell::new(data),
        }
    }

    /// Acquire the lock, disabling interrupts. Returns a guard that
    /// restores interrupts on drop.
    pub fn lock(&self) -> IrqSafeGuard<T> {
        let state = spin_lock_irqsave(&self.lock);
        IrqSafeGuard {
            lock: &self.lock,
            // SAFETY: mutual exclusion is guaranteed by the ticket lock.
            data: unsafe { &mut *self.data.get() },
            irq_state: state,
            _not_send_sync: PhantomData,
        }
    }

    /// Try to acquire without spinning. Returns None if held.
    pub fn try_lock(&self) -> Option<IrqSafeGuard<T>> {
        let state = crate::arch::arch_irq_save();
        if self.lock.try_lock() {
            Some(IrqSafeGuard {
                lock: &self.lock,
                // SAFETY: mutual exclusion is guaranteed by the ticket lock.
                data: unsafe { &mut *self.data.get() },
                irq_state: state,
                _not_send_sync: PhantomData,
            })
        } else {
            crate::arch::arch_irq_restore(state);
            None
        }
    }

    /// Acquire without touching IRQs. Asserts IRQs are already disabled.
    /// Used in multi-lock critical sections (Pattern B).
    pub fn spin_lock_noirq(&self) -> IrqSafeGuard<T> {
        debug_assert!(
            !crate::arch::arch_irq_enabled(),
            "spin_lock_noirq called with IRQs enabled"
        );
        self.lock.lock();
        IrqSafeGuard {
            lock: &self.lock,
            // SAFETY: mutual exclusion is guaranteed by the ticket lock.
            data: unsafe { &mut *self.data.get() },
            irq_state: IrqState::new(false),
            _not_send_sync: PhantomData,
        }
    }
}

// SAFETY: IrqSafeSpinlock provides interior mutability with mutual exclusion
// enforced by the ticket lock. SyncUnsafeCell already implements Sync.
unsafe impl<T: Send> Send for IrqSafeSpinlock<T> {}
unsafe impl<T: Send> Sync for IrqSafeSpinlock<T> {}

// ---------------------------------------------------------------------------
// IrqSafeGuard<T> — !Send + !Sync guard
// ---------------------------------------------------------------------------

pub struct IrqSafeGuard<'a, T> {
    lock: &'a RawSpinlock,
    data: &'a mut T,
    irq_state: IrqState,
    _not_send_sync: PhantomData<*mut ()>,
}

impl<T> Deref for IrqSafeGuard<'_, T> {
    type Target = T;
    fn deref(&self) -> &T {
        self.data
    }
}

impl<T> DerefMut for IrqSafeGuard<'_, T> {
    fn deref_mut(&mut self) -> &mut T {
        self.data
    }
}

impl<T> Drop for IrqSafeGuard<'_, T> {
    fn drop(&mut self) {
        spin_unlock_irqrestore(self.lock, self.irq_state);
    }
}

