const TCP_HDR_MIN_LEN: usize = 20;

const TCP_FIN: u8 = 0x01;
const TCP_SYN: u8 = 0x02;
const TCP_RST: u8 = 0x04;
const TCP_PSH: u8 = 0x08;
const TCP_ACK: u8 = 0x10;

const TCP_OPT_MSS: u8 = 2;
const TCP_MSS: u16 = 1460;

static INITIAL_SEQ: AtomicU32 = AtomicU32::new(0);

static TCP_CONNECTIONS: IrqSafeSpinlock<BTreeMap<(u16, u16, u32), Arc<Mutex<Socket>>>> =
    IrqSafeSpinlock::new(BTreeMap::new());

pub fn init() {
    info!("net/tcp: initialized");
}

fn rand_u32() -> u32 {
    let ts = tokei::current_time_ns();
    (ts as u32).wrapping_mul(1103515245).wrapping_add(12345)
}

pub fn receive(buf: NetworkBuffer, src_ip: u32, dst_ip: u32) {
    let payload = buf.payload();
    if payload.len() < TCP_HDR_MIN_LEN {
        return;
    }

    let src_port = ((payload[0] as u16) << 8) | (payload[1] as u16);
    let dst_port = ((payload[2] as u16) << 8) | (payload[3] as u16);
    let seq = u32::from_be_bytes([payload[4], payload[5], payload[6], payload[7]]);
    let ack = u32::from_be_bytes([payload[8], payload[9], payload[10], payload[11]]);
    let data_offset = payload[12] >> 4;
    let flags = payload[13];
    let window = ((payload[14] as u32) << 8) | (payload[15] as u32);

    let hdr_len = (data_offset as usize) * 4;
    if hdr_len < TCP_HDR_MIN_LEN || hdr_len > payload.len() {
        return;
    }

    let data = &payload[hdr_len..];

    let sock = TCP_CONNECTIONS
        .lock()
        .get(&(dst_port, src_port, src_ip))
        .cloned()
        .or_else(|| socket::find_listener(dst_port));

    let Some(sock) = sock else {
        if flags & TCP_RST == 0 {
            send_rst(src_ip, src_port, dst_ip, dst_port, seq);
        }
        return;
    };

    let mut s = sock.lock();

    if flags & TCP_RST != 0 {
        s.state = SocketState::Closed;
        return;
    }

    if flags & TCP_SYN != 0 {
        handle_syn(
            &mut s, &sock, src_ip, src_port, dst_ip, dst_port, seq, window,
        );
    }

    if !data.is_empty() && s.state == SocketState::Connected {
        s.recv_queue.push(data.to_vec());
        let new_ack = seq.wrapping_add(data.len() as u32);
        send_ack(
            src_ip,
            src_port,
            dst_ip,
            dst_port,
            s.local_seq,
            new_ack,
            65535,
        );
    }

    if flags & TCP_FIN != 0 {
        handle_fin(&mut s, src_ip, src_port, dst_ip, dst_port);
    }

    if flags & TCP_ACK != 0 && s.state == SocketState::Connecting {
        // SYN-ACK response to our SYN
        s.state = SocketState::Connected;
        // Send ACK to complete 3-way handshake
        send_ack(
            src_ip,
            src_port,
            dst_ip,
            dst_port,
            ack,
            seq.wrapping_add(1),
            65535,
        );
    }
}

fn handle_syn(
    sock: &mut Socket,
    sock_arc: &Arc<Mutex<Socket>>,
    src_ip: u32,
    src_port: u16,
    dst_ip: u32,
    dst_port: u16,
    remote_seq: u32,
    _remote_window: u32,
) {
    if sock.state == SocketState::Listening {
        let mut new_socket = Socket::new(SocketType::Tcp);
        new_socket.local_addr = sock.local_addr;
        new_socket.remote_addr = Some(SocketAddrV4::new(src_ip, src_port));
        new_socket.state = SocketState::Connected;

        let isn = INITIAL_SEQ.fetch_add(rand_u32(), Ordering::Relaxed);
        new_socket.local_seq = isn;

        let new_sock = Arc::new(Mutex::new(new_socket));
        socket::register_socket(new_sock.clone());

        sock.accept_queue.push(new_sock.clone());

        let key = (dst_port, src_port, src_ip);
        TCP_CONNECTIONS.lock().insert(key, new_sock);

        send_syn_ack(src_ip, src_port, dst_ip, dst_port, isn, remote_seq);
    }
}

fn handle_fin(sock: &mut Socket, src_ip: u32, src_port: u16, dst_ip: u32, dst_port: u16) {
    sock.recv_closed = true;
    if !sock.send_closed {
        send_fin(
            src_ip,
            src_port,
            dst_ip,
            dst_port,
            sock.local_seq,
            sock.remote_ack,
        );
        sock.send_closed = true;
    } else {
        send_ack(
            src_ip,
            src_port,
            dst_ip,
            dst_port,
            sock.local_seq,
            sock.remote_ack.wrapping_add(1),
            0,
        );
        sock.state = SocketState::Closed;
    }
}

