//! UDP (User Datagram Protocol) implementation.
//!
//! Simple, stateless transport protocol. Provides sendto/recvfrom semantics.

use alloc::sync::Arc;
use spin::Mutex;

use crate::net::buffer::NetworkBuffer;
use crate::net::ipv4::{self, IP_PROTO_UDP};
use crate::net::socket::{self, Socket, SocketAddrV4, SocketState};
use crate::syscall::errno::Errno;

const UDP_HDR_LEN: usize = 8;

pub fn init() {
    info!("net/udp: initialized");
}

pub fn receive(buf: NetworkBuffer, src_ip: u32, _dst_ip: u32) {
    let payload = buf.payload();
    if payload.len() < UDP_HDR_LEN {
        return;
    }

    let src_port = ((payload[0] as u16) << 8) | (payload[1] as u16);
    let dst_port = ((payload[2] as u16) << 8) | (payload[3] as u16);
    let length = ((payload[4] as usize) << 8) | (payload[5] as usize);

    if length < UDP_HDR_LEN || length > payload.len() {
        return;
    }

    let data = payload[UDP_HDR_LEN..length].to_vec();

    let sock = socket::find_socket(dst_port, src_ip);
    let Some(sock) = sock else {
        return;
    };

    let mut s = sock.lock();
    if s.state == SocketState::Closed {
        return;
    }

    if let Some(ref remote) = s.remote_addr {
        if remote.addr != src_ip || remote.port != src_port {
            return;
        }
    }

    s.recv_queue.push(data);
}

pub fn sendto(
    socket: &Arc<Mutex<Socket>>,
    data: &[u8],
    dest: Option<SocketAddrV4>,
) -> Result<usize, isize> {
    let (dst, need_ephemeral) = {
        let sock = socket.lock();
        let dst = match dest {
            Some(d) => d,
            None => match sock.remote_addr {
                Some(r) => r,
                None => return Err(Errno::EDESTADDRREQ.as_ret()),
            },
        };
        let need_eph = sock.local_addr.is_none();
        (dst, need_eph)
    };

    if need_ephemeral {
        if !socket::bind_ephemeral(socket, socket::our_ip()) {
            return Err(Errno::EADDRNOTAVAIL.as_ret());
        }
    }

    let src_port = socket
        .lock()
        .local_addr
        .as_ref()
        .map(|a| a.port)
        .unwrap_or(0);

    sendto_with_ports(socket, data, dst, src_port)
}

fn sendto_with_ports(
    socket: &Arc<Mutex<Socket>>,
    data: &[u8],
    dst: SocketAddrV4,
    src_port: u16,
) -> Result<usize, isize> {
    let mut header = [0u8; UDP_HDR_LEN];
    header[0] = (src_port >> 8) as u8;
    header[1] = (src_port & 0xff) as u8;
    header[2] = (dst.port >> 8) as u8;
    header[3] = (dst.port & 0xff) as u8;
    let udp_len = UDP_HDR_LEN + data.len();
    header[4] = (udp_len >> 8) as u8;
    header[5] = (udp_len & 0xff) as u8;
    header[6] = 0;
    header[7] = 0;

    let mut buf = NetworkBuffer::new(data.to_vec());
    buf.prepend(&header);

    ipv4::send(dst.addr, IP_PROTO_UDP, buf);

    Ok(data.len())
}

//! File-descriptor and VFS-related syscalls: openat, close, lseek,
//! stat, getdents, getcwd, chdir, dup, dup3, fcntl, ioctl.

use crate::arch::shared::syscall::SyscallRequest;
use crate::fs;
use crate::process;
use crate::syscall::errno::Errno;
use alloc::sync::Arc;

// ── open flags ────────────────────────────────────────────────────────────

const O_WRONLY: u32 = 1;
const O_RDWR: u32 = 2;
const O_CREAT: u32 = 0x40;
const O_EXCL: u32 = 0x80;
const O_TRUNC: u32 = 0x200;
const O_APPEND: u32 = 0x400;
const O_NONBLOCK: u32 = 0x800;
const O_NOCTTY: u32 = 0x100;
const O_NOFOLLOW: u32 = 0x20000;
const O_DIRECTORY: u32 = 0x10000;
const O_CLOEXEC: u32 = 0x80000;
const O_LARGEFILE: u32 = 0x8000;

/// Flags that openat is known to handle correctly.
const O_SUPPORTED: u32 = O_WRONLY
    | O_RDWR
    | O_CREAT
    | O_EXCL
    | O_TRUNC
    | O_APPEND
    | O_NONBLOCK
    | O_NOCTTY
    | O_NOFOLLOW
    | O_DIRECTORY
    | O_CLOEXEC
    | O_LARGEFILE;

const AT_SYMLINK_NOFOLLOW: usize = 0x100;
const AT_EACCESS: usize = 0x200;
const AT_REMOVEDIR: usize = 0x200;
const AT_EMPTY_PATH: usize = 0x1000;

// ── stat mode bits ────────────────────────────────────────────────────────

const S_IFREG: u32 = 0o100000;
const S_IFDIR: u32 = 0o040000;
const S_IFCHR: u32 = 0o020000;
const S_IFBLK: u32 = 0o060000;

// ── dirent types ──────────────────────────────────────────────────────────

const DT_DIR: u8 = 4;
const DT_REG: u8 = 8;
const DT_CHR: u8 = 2;
const DT_BLK: u8 = 6;

// ── sys_openat ────────────────────────────────────────────────────────────

const AT_FDCWD: isize = -100;

/// Map a VFS `FsError` to a Linux-negative errno value.
pub(crate) fn fs_error_to_errno(e: crate::fs::FsError) -> isize {
    match e {
        crate::fs::FsError::NotInitialized => Errno::ENODEV.as_ret(),
        crate::fs::FsError::InvalidPath => Errno::ENOENT.as_ret(),
        crate::fs::FsError::NotFound => Errno::ENOENT.as_ret(),
        crate::fs::FsError::AlreadyExists => Errno::EEXIST.as_ret(),
        crate::fs::FsError::NotDirectory => Errno::ENOTDIR.as_ret(),
        crate::fs::FsError::IsDirectory => Errno::EISDIR.as_ret(),
        crate::fs::FsError::NotEmpty => Errno::ENOTEMPTY.as_ret(),
        crate::fs::FsError::Io => Errno::EIO.as_ret(),
        crate::fs::FsError::Unsupported => Errno::ENOSYS.as_ret(),
        crate::fs::FsError::WouldBlock => Errno::EAGAIN.as_ret(),
        crate::fs::FsError::BrokenPipe => Errno::EPIPE.as_ret(),
    }
}

pub fn sys_openat(req: &SyscallRequest) -> isize {
    let dirfd = req.arg0 as isize;
    let path_ptr = req.arg1 as u64;
    let flags = req.arg2 as u32;
    let _mode = req.arg3;

    // Reject unsupported flag bits.
    let access_mode = flags & 3;
    let extra = flags & !3; // flags without access mode
    if extra & !O_SUPPORTED != 0 {
        return Errno::EINVAL.as_ret();
    }

    // Validate access-mode + flag combinations.
    if access_mode > 2 {
        return Errno::EINVAL.as_ret();
    }
    if flags & O_TRUNC != 0 && access_mode == 0 {
        return Errno::EINVAL.as_ret();
    }
    if flags & O_DIRECTORY != 0 && access_mode != 0 {
        return Errno::EINVAL.as_ret();
    }

    let path = match read_user_str(path_ptr, 256) {
        Ok(p) => p,
        Err(e) => return e,
    };
    if path.is_empty() {
        return Errno::ENOENT.as_ret();
    }
    let full_path = match resolve_path_at(dirfd, &path) {
        Ok(p) => p,
        Err(e) => return e,
    };

    let (node, created) = if flags & O_CREAT != 0 {
        match fs::create_file(&full_path) {
            Ok(n) => (n, true),
            Err(fs::FsError::AlreadyExists) => {
                if flags & O_EXCL != 0 {
                    return Errno::EEXIST.as_ret();
                }
                match fs::lookup(&full_path) {
                    Ok(n) => (n, false),
                    Err(e) => return fs_error_to_errno(e),
                }
            }
            Err(e) => return fs_error_to_errno(e),
        }
    } else {
        match fs::lookup(&full_path) {
            Ok(n) => (n, false),
            Err(e) => return fs_error_to_errno(e),
        }
    };

    if flags & O_DIRECTORY != 0 {
        match node.metadata() {
            Ok(meta) if meta.kind == fs::NodeKind::Directory => {}
            Ok(_) => return Errno::ENOTDIR.as_ret(),
            Err(e) => return fs_error_to_errno(e),
        }
    }

    // Truncate the opened file to zero length in place.
    if flags & O_TRUNC != 0 {
        if let Err(e) = node.truncate(0) {
            return fs_error_to_errno(e);
        }
    }

    let file = fs::file_table::OpenFile::new(node, flags & !O_CLOEXEC, 0);

    let tid = crate::sched::current_tid().unwrap_or(0) as process::Tid;
