const CLONE_ACCEPTED: usize = CLONE_REQUIRED
    | CLONE_SETTLS
    | CLONE_PARENT_SETTID
    | CLONE_CHILD_SETTID
    | CLONE_CHILD_CLEARTID
    | CLONE_SYSVSEM
    | CLONE_DETACHED;

#[derive(Debug, Clone, Copy, Default)]
struct Clone3Args {
    flags: u64,
    pidfd: u64,
    child_tid: u64,
    parent_tid: u64,
    exit_signal: u64,
    stack: u64,
    stack_size: u64,
    tls: u64,
    set_tid: u64,
    set_tid_size: u64,
    cgroup: u64,
}

fn clone3_unknown_tail_range(size: usize) -> Result<Option<core::ops::Range<usize>>, isize> {
    if size < CLONE_ARGS_SIZE_VER0 {
        return Err(Errno::EINVAL.as_ret());
    }
    if size > CLONE_ARGS_SIZE_MAX {
        return Err(Errno::E2BIG.as_ret());
    }
    if size > CLONE_ARGS_SIZE_VER2 {
        Ok(Some(CLONE_ARGS_SIZE_VER2..size))
    } else {
        Ok(None)
    }
}

fn read_clone3_args(user_ptr: u64, size: usize) -> Result<Clone3Args, isize> {
    if user_ptr == 0 {
        return Err(Errno::EFAULT.as_ret());
    }
    if let Some(tail) = clone3_unknown_tail_range(size)? {
        for offset in tail {
            let va = user_ptr
                .checked_add(offset as u64)
                .ok_or(Errno::EFAULT.as_ret())?;
            match read_u8_from_user(va) {
                Some(0) => {}
                Some(_) => return Err(Errno::E2BIG.as_ret()),
                None => return Err(Errno::EFAULT.as_ret()),
            }
        }
    }

    let read_field = |offset: u64| -> Result<u64, isize> {
        let va = user_ptr.checked_add(offset).ok_or(Errno::EFAULT.as_ret())?;
        read_u64_from_user(va).ok_or(Errno::EFAULT.as_ret())
    };
    let read_optional_field = |offset: u64| -> Result<u64, isize> {
        if (offset as usize) + core::mem::size_of::<u64>() <= size {
            read_field(offset)
        } else {
            Ok(0)
        }
    };

    Ok(Clone3Args {
        flags: read_field(0)?,
        pidfd: read_field(8)?,
        child_tid: read_field(16)?,
        parent_tid: read_field(24)?,
        exit_signal: read_field(32)?,
        stack: read_field(40)?,
        stack_size: read_field(48)?,
        tls: read_field(56)?,
        set_tid: read_optional_field(64)?,
        set_tid_size: read_optional_field(72)?,
        cgroup: read_optional_field(80)?,
    })
}

fn clone3_legacy_request_from_args(args: Clone3Args) -> Result<SyscallRequest, isize> {
    if args.pidfd != 0 || args.set_tid != 0 || args.set_tid_size != 0 || args.cgroup != 0 {
        return Err(Errno::EINVAL.as_ret());
    }
    if args.exit_signal > CLONE_EXIT_SIGNAL_MASK as u64 {
        return Err(Errno::EINVAL.as_ret());
    }
    if args.flags & CLONE_EXIT_SIGNAL_MASK as u64 != 0 {
        return Err(Errno::EINVAL.as_ret());
    }

    let child_stack = if args.stack == 0 {
        if args.stack_size != 0 {
            return Err(Errno::EINVAL.as_ret());
        }
        0
    } else {
        if args.stack_size == 0 {
            return Err(Errno::EINVAL.as_ret());
        }
        args.stack
            .checked_add(args.stack_size)
            .ok_or(Errno::EINVAL.as_ret())?
    };

    Ok(SyscallRequest {
        number: crate::syscall::numbers::SYS_CLONE,
        arg0: (args.flags | args.exit_signal) as usize,
        arg1: child_stack as usize,
        arg2: args.parent_tid as usize,
        arg3: args.tls as usize,
        arg4: args.child_tid as usize,
        arg5: 0,
    })
}

