pub fn root() -> NodeRef {
    Arc::new(RamNode::new_dir())
}

struct RamNode {
    inner: Mutex<RamNodeInner>,
}

struct RamNodeInner {
    kind: RamNodeKind,
}

enum RamNodeKind {
    Directory { entries: Vec<RamEntry> },
    Regular { data: Vec<u8> },
    Symlink { target: String },
}

struct RamEntry {
    name: String,
    node: NodeRef,
}

impl RamNode {
    fn new_dir() -> Self {
        Self {
            inner: Mutex::new(RamNodeInner {
                kind: RamNodeKind::Directory {
                    entries: Vec::new(),
                },
            }),
        }
    }

    fn new_file() -> Self {
        Self {
            inner: Mutex::new(RamNodeInner {
                kind: RamNodeKind::Regular { data: Vec::new() },
            }),
        }
    }

    pub fn new_symlink(target: String) -> Self {
        Self {
            inner: Mutex::new(RamNodeInner {
                kind: RamNodeKind::Symlink { target },
            }),
        }
    }

    fn check_name(name: &str) -> Result<()> {
        if name.is_empty() || name == "." || name == ".." || name.as_bytes().contains(&b'/') {
            return Err(FsError::InvalidPath);
        }
        Ok(())
    }
}

impl Vnode for RamNode {
    fn metadata(&self) -> Result<Metadata> {
        let inner = self.inner.lock();
        Ok(match &inner.kind {
            RamNodeKind::Directory { entries } => Metadata {
                kind: NodeKind::Directory,
                len: entries.len(),
            },
            RamNodeKind::Regular { data } => Metadata {
                kind: NodeKind::Regular,
                len: data.len(),
            },
            RamNodeKind::Symlink { .. } => Metadata {
                kind: NodeKind::Regular,
                len: 0,
            },
        })
    }

    fn lookup(&self, name: &str) -> Result<NodeRef> {
        Self::check_name(name)?;

        let inner = self.inner.lock();
        let RamNodeKind::Directory { entries } = &inner.kind else {
            return Err(FsError::NotDirectory);
        };

        entries
            .iter()
            .find(|entry| entry.name == name)
            .map(|entry| entry.node.clone())
            .ok_or(FsError::NotFound)
    }

    fn create_file(&self, name: &str) -> Result<NodeRef> {
        Self::check_name(name)?;
        let node: NodeRef = Arc::new(RamNode::new_file());
        let entry_name = String::from(name);

        let mut inner = self.inner.lock();
        let RamNodeKind::Directory { entries } = &mut inner.kind else {
            return Err(FsError::NotDirectory);
        };

        if entries.iter().any(|entry| entry.name == name) {
            return Err(FsError::AlreadyExists);
        }

        entries.push(RamEntry {
            name: entry_name,
            node: node.clone(),
        });
        Ok(node)
    }

    fn mkdir(&self, name: &str) -> Result<NodeRef> {
        Self::check_name(name)?;

        let mut inner = self.inner.lock();
        let RamNodeKind::Directory { entries } = &mut inner.kind else {
            return Err(FsError::NotDirectory);
        };

        if entries.iter().any(|entry| entry.name == name) {
            return Err(FsError::AlreadyExists);
        }

        let node: NodeRef = Arc::new(RamNode::new_dir());
        entries.push(RamEntry {
            name: String::from(name),
            node: node.clone(),
        });
        Ok(node)
    }

    fn readdir(&self) -> Result<Vec<DirEntry>> {
        // Snapshot child names and refs under the directory lock, then drop
        // it before calling metadata() on each child to avoid lock nesting
        // or holding the directory lock across arbitrary vnode code.
        let children: Vec<(alloc::string::String, NodeRef)> = {
            let inner = self.inner.lock();
            let RamNodeKind::Directory { entries } = &inner.kind else {
                return Err(FsError::NotDirectory);
            };
            entries
                .iter()
                .map(|e| (e.name.clone(), e.node.clone()))
                .collect()
        };

        let mut out = Vec::new();
        for (name, node) in children {
            out.push(DirEntry {
                name,
                kind: node.metadata()?.kind,
            });
        }
        Ok(out)
    }

    fn unlink(&self, name: &str) -> Result<()> {
        Self::check_name(name)?;

        let mut inner = self.inner.lock();
        let RamNodeKind::Directory { entries } = &mut inner.kind else {
            return Err(FsError::NotDirectory);
        };

        let index = entries
            .iter()
            .position(|entry| entry.name == name)
            .ok_or(FsError::NotFound)?;
        let child = entries[index].node.clone();
        let metadata = child.metadata()?;
        if metadata.kind == NodeKind::Directory && metadata.len != 0 {
            return Err(FsError::NotEmpty);
        }

        entries.remove(index);
        Ok(())
    }

    fn read_at(&self, offset: usize, buf: &mut [u8]) -> Result<usize> {
        let inner = self.inner.lock();
        let RamNodeKind::Regular { data } = &inner.kind else {
            return Err(FsError::IsDirectory);
        };

        if offset >= data.len() {
            return Ok(0);
        }

        let n = buf.len().min(data.len() - offset);
        buf[..n].copy_from_slice(&data[offset..offset + n]);
        Ok(n)
    }

use super::{FsError, Metadata, NodeKind, NodeRef, Result, Vnode};
use alloc::sync::Arc;
use alloc::vec::Vec;
use spin::Mutex;

const PIPE_BUF_SIZE: usize = 65536;

struct PipeBuffer {
    buf: Vec<u8>,
    read_pos: usize,
    write_pos: usize,
    byte_count: usize,
    read_closed: bool,
    write_closed: bool,
    waiters: Vec<usize>,
}

impl PipeBuffer {
    fn new() -> Self {
        Self {
            buf: alloc::vec![0u8; PIPE_BUF_SIZE],
            read_pos: 0,
            write_pos: 0,
            byte_count: 0,
            read_closed: false,
            write_closed: false,
            waiters: Vec::new(),
        }
    }

    fn wake_waiters(&self) {
        for &tid in &self.waiters {
            crate::sched::wake_up(tid);
        }
    }

    fn read_ready(&self) -> bool {
        self.byte_count > 0 || self.write_closed
    }

    fn write_ready(&self) -> bool {
        !self.read_closed && self.byte_count < PIPE_BUF_SIZE
    }
}

pub struct PipeEnd {
    inner: Arc<Mutex<PipeBuffer>>,
    is_read_end: bool,
}

impl PipeEnd {
    pub fn new_pair() -> (NodeRef, NodeRef) {
        let buf = Arc::new(Mutex::new(PipeBuffer::new()));
        let reader: NodeRef = Arc::new(PipeEnd {
            inner: Arc::clone(&buf),
            is_read_end: true,
        });
        let writer: NodeRef = Arc::new(PipeEnd {
            inner: Arc::clone(&buf),
            is_read_end: false,
        });
        (reader, writer)
    }
}

impl Vnode for PipeEnd {
    fn metadata(&self) -> Result<Metadata> {
        Ok(Metadata {
            kind: NodeKind::Regular,
            len: 0,
        })
    }

    fn is_seekable(&self) -> bool {
        false
    }

    fn read_at(&self, _offset: usize, buf: &mut [u8]) -> Result<usize> {
        if !self.is_read_end {
            return Err(FsError::Unsupported);
        }
        if buf.is_empty() {
            return Ok(0);
        }
        let mut inner = self.inner.lock();
        if inner.byte_count == 0 {
            if inner.write_closed {
                return Ok(0);
            }
            return Err(FsError::WouldBlock);
        }
        let n = buf.len().min(inner.byte_count);
        for i in 0..n {
            let pos = inner.read_pos;
            buf[i] = inner.buf[pos];
            inner.read_pos = (pos + 1) % PIPE_BUF_SIZE;
        }
        inner.byte_count -= n;
        inner.wake_waiters();
        Ok(n)
    }

    fn write_at(&self, _offset: usize, data: &[u8]) -> Result<usize> {
        if self.is_read_end {
            return Err(FsError::Unsupported);
        }
        if data.is_empty() {
            return Ok(0);
        }
        let mut inner = self.inner.lock();
        if inner.read_closed {
            return Err(FsError::BrokenPipe);
        }
        let space = PIPE_BUF_SIZE - inner.byte_count;
        if space == 0 {
            return Err(FsError::WouldBlock);
        }
        let n = data.len().min(space);
        for i in 0..n {
            let pos = inner.write_pos;
            inner.buf[pos] = data[i];
            inner.write_pos = (pos + 1) % PIPE_BUF_SIZE;
        }
        inner.byte_count += n;
        inner.wake_waiters();
        Ok(n)
    }

    fn poll_read_ready(&self) -> bool {
        if !self.is_read_end {
            return false;
        }
        self.inner.lock().read_ready()
    }

    fn poll_write_ready(&self) -> bool {
        if self.is_read_end {
            return false;
        }
        self.inner.lock().write_ready()
    }
}

impl Drop for PipeEnd {
    fn drop(&mut self) {
        let mut guard = self.inner.lock();
        if self.is_read_end {
            guard.read_closed = true;
        } else {
            guard.write_closed = true;
        }
        guard.wake_waiters();
    }
}

