    }

    fn poll_write_ready(&self) -> bool {
        self.outgoing.lock().write_ready()
    }
}

impl Drop for UnixStreamEnd {
    fn drop(&mut self) {
        {
            let mut incoming = self.incoming.lock();
            incoming.read_closed = true;
            incoming.wake_waiters();
        }
        {
            let mut outgoing = self.outgoing.lock();
            outgoing.write_closed = true;
            outgoing.wake_waiters();
        }
    }
}

