fn main() {
    let target = env::var("TARGET").unwrap();

    let (script, init_elf) = if target.starts_with("riscv64") {
        (RISCV64_LINKER_SCRIPT, "src/init-riscv64.elf")
    } else if target.starts_with("loongarch64") {
        (LOONGARCH64_LINKER_SCRIPT, "src/init-loongarch64.elf")
    } else {
        return;
    };

    let out_dir = PathBuf::from(env::var("OUT_DIR").unwrap());

    // Generate linker script.
    let ld_path = out_dir.join("linker.ld");
    let mut f = fs::File::create(&ld_path).unwrap();
    f.write_all(script.as_bytes()).unwrap();
    println!("cargo::rustc-link-arg=-T{}", ld_path.display());

    // Generate initramfs cpio from the init ELF.
    let init_data = fs::read(init_elf).expect("failed to read init ELF");
    let cpio_data = build_newc_cpio("init", &init_data);
    let cpio_path = out_dir.join("initramfs.cpio");
    fs::write(&cpio_path, &cpio_data).expect("failed to write initramfs cpio");
}

/// Build a minimal newc cpio archive containing a single file.
fn build_newc_cpio(name: &str, data: &[u8]) -> Vec<u8> {
    let name_with_nul = format!("{}\0", name);
    let namesize = name_with_nul.len() as u32;
    let filesize = data.len() as u32;

    // newc header: 110 bytes, all fields 8-digit hex ASCII, NUL-terminated.
    let mut header = [b'0'; 110];
    header[0..6].copy_from_slice(b"070701");
    write_hex8(&mut header[6..14], 1); // ino
    write_hex8(&mut header[14..22], 0x81a4); // mode (S_IFREG | 0644)
    write_hex8(&mut header[22..30], 0); // uid
    write_hex8(&mut header[30..38], 0); // gid
    write_hex8(&mut header[38..46], 1); // nlink
    write_hex8(&mut header[46..54], 0); // mtime
    write_hex8(&mut header[54..62], filesize);
    write_hex8(&mut header[62..70], 0); // devmajor
    write_hex8(&mut header[70..78], 0); // devminor
    write_hex8(&mut header[78..86], 0); // rdevmajor
    write_hex8(&mut header[86..94], 0); // rdevminor
    write_hex8(&mut header[94..102], namesize);
    write_hex8(&mut header[102..110], 0); // check

    let mut out = Vec::new();
    out.extend_from_slice(&header);
    out.extend_from_slice(name_with_nul.as_bytes());

    // Pad name to 4-byte boundary.
    let name_pad = pad4(out.len());
    out.resize(out.len() + name_pad, 0);

    out.extend_from_slice(data);

    // Pad data to 4-byte boundary.
    let data_pad = pad4(out.len());
    out.resize(out.len() + data_pad, 0);

    // Trailer entry.
    let mut trailer = [b'0'; 110];
    trailer[0..6].copy_from_slice(b"070701");
    write_hex8(&mut trailer[6..14], 0);
    write_hex8(&mut trailer[14..22], 0);
    write_hex8(&mut trailer[22..30], 0);
    write_hex8(&mut trailer[30..38], 0);
    write_hex8(&mut trailer[38..46], 1);
    write_hex8(&mut trailer[46..54], 0);
    write_hex8(&mut trailer[54..62], 0);
    write_hex8(&mut trailer[62..70], 0);
    write_hex8(&mut trailer[70..78], 0);
    write_hex8(&mut trailer[78..86], 0);
    write_hex8(&mut trailer[86..94], 0);
    write_hex8(&mut trailer[94..102], 11); // "TRAILER!!!\0"
    write_hex8(&mut trailer[102..110], 0);

    out.extend_from_slice(&trailer);
    out.extend_from_slice(b"TRAILER!!!\0");

    let trailer_pad = pad4(out.len());
    out.resize(out.len() + trailer_pad, 0);

    out
}

fn write_hex8(buf: &mut [u8], val: u32) {
    let s = format!("{:08X}", val);
    buf.copy_from_slice(s.as_bytes());
}

const fn pad4(offset: usize) -> usize {
    (4 - (offset & 3)) & 3
}

