    pub(crate) adapter: Arc<Ext4BlockAdapter>,
    pub(crate) lock: Mutex<()>,
    inode_cache: Mutex<BTreeMap<u32, CachedInodeMeta>>,
    /// (parent_inode, name) → child inode + mode, populated by readdir
    /// and lookup. Avoids repeated dir_get_entries + linear scans.
