impl Ext4Fs {
    pub fn mount(dev: Arc<dyn crate::fs::block::BlockDevice>) -> Result<Arc<Self>> {
        let adapter = Arc::new(Ext4BlockAdapter::new(dev));
        let ext4_dev: Arc<dyn Ext4BlockDevice> = adapter.clone();

        // Pre-validate the ext4 superblock before Ext4::open(),
        // which builds internal state and may panic on non-ext4 or
        // malformed disks (e.g. divide-by-zero when s_blocks_per_group == 0).
        // Magic (0xEF53) is at offset 56 within the superblock struct,
        // which starts at byte 1024 on disk.
        // s_blocks_per_group is at offset 1024+32=1056 (u32 LE).
        // s_log_block_size is at offset 1024+24=1048 (u32 LE).
        // s_desc_size is at offset 1024+254=1278 (u16 LE).
        const SUPERBLOCK_MAGIC_OFFSET: usize = 1024 + 56;
        const SUPERBLOCK_BLOCKS_PER_GROUP_OFFSET: usize = 1024 + 32;
        const SUPERBLOCK_LOG_BLOCK_SIZE_OFFSET: usize = 1024 + 24;
        const SUPERBLOCK_DESC_SIZE_OFFSET: usize = 1024 + 254;
        const EXT4_MIN_DESC_SIZE: u16 = 32;
        let probe = adapter.read_offset(0);
        if probe.len() <= SUPERBLOCK_DESC_SIZE_OFFSET + 1 {
            return Err(FsError::Unsupported);
        }
        let magic = u16::from_le_bytes([
            probe[SUPERBLOCK_MAGIC_OFFSET],
            probe[SUPERBLOCK_MAGIC_OFFSET + 1],
        ]);
        if magic != 0xEF53 {
            return Err(FsError::Unsupported);
        }
        let blocks_per_group = u32::from_le_bytes([
            probe[SUPERBLOCK_BLOCKS_PER_GROUP_OFFSET],
            probe[SUPERBLOCK_BLOCKS_PER_GROUP_OFFSET + 1],
            probe[SUPERBLOCK_BLOCKS_PER_GROUP_OFFSET + 2],
            probe[SUPERBLOCK_BLOCKS_PER_GROUP_OFFSET + 3],
        ]);
        let log_block_size = u32::from_le_bytes([
            probe[SUPERBLOCK_LOG_BLOCK_SIZE_OFFSET],
            probe[SUPERBLOCK_LOG_BLOCK_SIZE_OFFSET + 1],
            probe[SUPERBLOCK_LOG_BLOCK_SIZE_OFFSET + 2],
            probe[SUPERBLOCK_LOG_BLOCK_SIZE_OFFSET + 3],
        ]);
        let Some(block_size) = 1024usize.checked_shl(log_block_size) else {
            return Err(FsError::Unsupported);
        };
        if blocks_per_group == 0 {
            return Err(FsError::Unsupported);
        }
        if block_size != 4096 {
            return Err(FsError::Unsupported);
        }
        let raw_desc_size = u16::from_le_bytes([
            probe[SUPERBLOCK_DESC_SIZE_OFFSET],
            probe[SUPERBLOCK_DESC_SIZE_OFFSET + 1],
        ]);
        let desc_size = raw_desc_size.max(EXT4_MIN_DESC_SIZE);
        if desc_size as usize > block_size {
            return Err(FsError::Unsupported);
        }

        adapter.clear_error();
        let ext4 = Ext4::open(ext4_dev);
        if adapter.take_error() {
            return Err(FsError::Io);
        }

        let block_size = ext4.super_block.block_size();
        if block_size != 4096 {
            return Err(FsError::Unsupported);
        }
        let inode_size = ext4.super_block.inode_size();
        if inode_size < 128 {
            return Err(FsError::Unsupported);
        }

        let incompat = ext4.super_block.incompat_features();
        let unsupported = incompat & !SUPPORTED_INCOMPAT_FEATURES;
        if unsupported != 0 {
            warn!("ext4: unsupported incompat features {:#010x}", unsupported);
            return Err(FsError::Unsupported);
        }

        adapter.clear_error();
        let root_ref = ext4.get_inode_ref(2);
        if adapter.take_error() {
            return Err(FsError::Io);
        }
        if !root_ref.inode.is_dir() {
            return Err(FsError::Unsupported);
        }

        Ok(Arc::new(Self {
            ext4,
            adapter,
            lock: Mutex::new(()),
            inode_cache: Mutex::new(BTreeMap::new()),
            lookup_cache: Mutex::new(BTreeMap::new()),
        }))
    }

    fn check_io(&self) -> Result<()> {
        if self.adapter.take_error() {
            return Err(FsError::Io);
        }
        Ok(())
    }

    pub fn root_node(self: &Arc<Self>) -> NodeRef {
        Arc::new(Ext4Vnode {
            fs: Arc::clone(self),
            path: String::from("/"),
            inode: 2,
            mode: InodeFileType::S_IFDIR.bits(),
        })
    }

    /// Create a Vnode directly from an inode number, bypassing path-based
    /// lookup. Used when readdir has already identified the entry.
    pub fn vnode_from_inode(
        self: &Arc<Self>,
        inode_num: u32,
        path: alloc::string::String,
    ) -> Option<NodeRef> {
        let _guard = self.lock.lock();
        self.adapter.clear_error();
        let inode_ref = self.ext4.get_inode_ref(inode_num);
        if self.adapter.take_error() {
            return None;
        }
        let mode = if inode_ref.inode.is_dir() {
            InodeFileType::S_IFDIR.bits()
        } else {
            InodeFileType::S_IFREG.bits()
        };
        let size = inode_ref.inode.size();

        self.inode_cache
            .lock()
            .insert(inode_num, inode_to_cached_meta(mode, size));

        Some(Arc::new(Ext4Vnode {
            fs: Arc::clone(self),
            path,
            inode: inode_num,
            mode,
        }))
    }

