struct TestManifest {
    name: String,
    kind: String,
    source: String,
    expect_exit: Option<i32>,
    stdout_contains: Option<String>,
    initramfs: Option<String>,
    disk_image: Option<String>,
    timeout: Option<u64>,
}

/// Parse a simple key = "value" TOML-like manifest.
/// Does not handle tables or arrays — only top-level key-value pairs.
fn parse_manifest(raw: &str) -> Result<TestManifest, String> {
    let mut map: HashMap<String, String> = HashMap::new();
    for line in raw.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        let (key, val) = line
            .split_once('=')
            .ok_or_else(|| format!("expected key = value, got: {}", line))?;
        let key = key.trim().to_string();
        let val = val.trim().trim_matches('"').to_string();
        map.insert(key, val);
    }
    let get = |k: &str| {
        map.get(k)
            .cloned()
            .ok_or_else(|| format!("missing field: {}", k))
    };
    Ok(TestManifest {
        name: get("name")?,
        kind: get("kind")?,
        source: get("source")?,
        expect_exit: map
            .get("expect_exit")
            .map(|v| v.parse().map_err(|e| format!("expect_exit: {}", e)))
            .transpose()?,
        stdout_contains: map.get("stdout_contains").cloned(),
        initramfs: map.get("initramfs").cloned(),
        disk_image: map.get("disk_image").cloned(),
        timeout: map
            .get("timeout")
            .map(|v| v.parse().map_err(|e| format!("timeout: {}", e)))
            .transpose()?,
    })
}

