#[repr(C, align(16))]
struct VirtqDesc {
    addr: u64,
    len: u32,
    flags: u16,
    next: u16,
}

#[repr(C, align(2))]
struct VirtqAvail {
    flags: u16,
    idx: u16,
    ring: [u16; MAX_QUEUE_SIZE],
}

#[repr(C, align(4))]
struct VirtqUsed {
    flags: u16,
    idx: u16,
    ring: [VirtqUsedElem; MAX_QUEUE_SIZE],
}

#[repr(C)]
struct VirtqUsedElem {
    id: u32,
    len: u32,
}

#[repr(C)]
struct BlkRequestHeader {
    typ: u32,
    reserved: u32,
    sector: u64,
}

impl VirtioBlk {
    pub unsafe fn init(base: usize) -> Option<Self> {
        let ptr = base as *mut u32;

        let magic = unsafe { ptr.read_volatile() };
        if magic != 0x74726976 {
            return None;
        }

        let version = unsafe { ptr.add(1).read_volatile() };
        if version != 1 {
            return None;
        }

        let device_id = unsafe { ptr.add(2).read_volatile() };
        if device_id != 2 {
            return None;
        }

        // Reset
        unsafe { ptr.add(0x070 / 4).write_volatile(0) };
        fence(Ordering::SeqCst);

        // Acknowledge
        unsafe { ptr.add(0x070 / 4).write_volatile(1) };
        fence(Ordering::SeqCst);

        // Driver
        unsafe { ptr.add(0x070 / 4).write_volatile(3) };
        fence(Ordering::SeqCst);

        let queue_num_max = unsafe { ptr.add(0x034 / 4).read_volatile() } as u16;
        // We use descriptors 0, 1, and 2 for each request.
        if queue_num_max < 3 {
            return None;
