//! Socket layer: socket types, address management, and integration with
//! the file descriptor table.
//!
//! Supports `AF_INET` with `SOCK_STREAM` (TCP) and `SOCK_DGRAM` (UDP).

use alloc::collections::BTreeMap;
use alloc::sync::Arc;
use alloc::vec::Vec;
use core::sync::atomic::{AtomicU64, Ordering};
use spin::Mutex;

use crate::fs::Metadata;
use crate::fs::Vnode;
use crate::sync::IrqSafeSpinlock;

pub const AF_INET: u16 = 2;

pub const SOCK_STREAM: u32 = 1;
pub const SOCK_DGRAM: u32 = 2;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct SocketAddrV4 {
    pub addr: u32,
    pub port: u16,
}

impl SocketAddrV4 {
    pub fn new(addr: u32, port: u16) -> Self {
        Self { addr, port }
    }

    pub fn from_bytes(data: &[u8]) -> Option<Self> {
        if data.len() < 8 {
            return None;
        }
        let addr = u32::from_be_bytes([data[4], data[5], data[6], data[7]]);
        let port = ((data[2] as u16) << 8) | (data[3] as u16);
        Some(Self { addr, port })
    }

    pub fn to_bytes(&self) -> [u8; 16] {
        let mut bytes = [0u8; 16];
        bytes[0] = (AF_INET & 0xff) as u8;
        bytes[1] = ((AF_INET >> 8) & 0xff) as u8;
        bytes[2] = (self.port >> 8) as u8;
        bytes[3] = (self.port & 0xff) as u8;
        bytes[4..8].copy_from_slice(&self.addr.to_be_bytes());
        bytes
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SocketType {
    Tcp,
    Udp,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SocketState {
    Closed,
    Created,
    Bound,
    Listening,
    Connecting,
    Connected,
}

pub struct Socket {
    pub id: u64,
    pub socket_type: SocketType,
    pub local_addr: Option<SocketAddrV4>,
    pub remote_addr: Option<SocketAddrV4>,
    pub state: SocketState,
    pub listen_backlog: usize,
    pub accept_queue: Vec<Arc<Mutex<Socket>>>,
    pub recv_queue: Vec<Vec<u8>>,
    pub recv_closed: bool,
    pub send_closed: bool,
    pub reuseaddr: bool,
    pub keepalive: bool,
    pub broadcast: bool,
    pub tcp_nodelay: bool,
    pub error: Option<i32>,
    // TCP sequence numbers (unused for UDP)
    pub local_seq: u32,
    pub remote_ack: u32,
}

impl Socket {
    pub fn new(socket_type: SocketType) -> Self {
        static NEXT_ID: AtomicU64 = AtomicU64::new(1);
        Self {
            id: NEXT_ID.fetch_add(1, Ordering::Relaxed),
            socket_type,
            local_addr: None,
            remote_addr: None,
            state: SocketState::Created,
            listen_backlog: 0,
            accept_queue: Vec::new(),
            recv_queue: Vec::new(),
            recv_closed: false,
            send_closed: false,
            reuseaddr: false,
            keepalive: false,
            broadcast: false,
            tcp_nodelay: false,
            error: None,
            local_seq: 0,
            remote_ack: 0,
        }
    }
}

// Global registries
static SOCKET_REGISTRY: IrqSafeSpinlock<BTreeMap<u64, Arc<Mutex<Socket>>>> =
    IrqSafeSpinlock::new(BTreeMap::new());

static BOUND_SOCKETS: IrqSafeSpinlock<BTreeMap<u16, Arc<Mutex<Socket>>>> =
    IrqSafeSpinlock::new(BTreeMap::new());

static TCP_LISTENER: IrqSafeSpinlock<BTreeMap<u16, Arc<Mutex<Socket>>>> =
    IrqSafeSpinlock::new(BTreeMap::new());

pub fn init() {
    info!("net/socket: initialized");
}

pub fn register_socket(socket: Arc<Mutex<Socket>>) {
    let id = socket.lock().id;
    SOCKET_REGISTRY.lock().insert(id, socket);
}

pub fn lookup_socket(id: u64) -> Option<Arc<Mutex<Socket>>> {
    SOCKET_REGISTRY.lock().get(&id).cloned()
}

pub fn unregister_socket(socket: &Arc<Mutex<Socket>>) {
    let id = socket.lock().id;
    SOCKET_REGISTRY.lock().remove(&id);
}

/// Get socket by fd (via vnode's socket_id).
pub fn socket_by_fd(tid: u32, fd: usize) -> Option<Arc<Mutex<Socket>>> {
    let result = crate::process::with_thread(tid, |thread| {
        let proc = thread.proc.as_ref()?.upgrade()?;
        let guard = proc.lock();
        let files = guard.files.as_ref()?;
        let open_file = files.get(fd)?;
        let id = open_file.node.as_ref().socket_id()?;
        drop(guard);
        drop(proc);
        SOCKET_REGISTRY.lock().get(&id).cloned()
    });
    match result {
        Some(inner) => inner,
        None => None,
    }
}

pub fn bind_socket(socket: &Arc<Mutex<Socket>>, addr: SocketAddrV4) -> bool {
    let port = addr.port;
    if port == 0 {
        return bind_ephemeral(socket, addr.addr);
    }
    let sock = socket.lock();
    let existing = BOUND_SOCKETS.lock().get(&port).cloned();
    if let Some(existing) = existing {
        let ex = existing.lock();
        if !ex.reuseaddr && !sock.reuseaddr {
            return false;
        }
    }
    BOUND_SOCKETS.lock().insert(port, socket.clone());
    true
}

pub fn bind_ephemeral(socket: &Arc<Mutex<Socket>>, addr: u32) -> bool {
    let mut bound = BOUND_SOCKETS.lock();
    for port in 49152u16..=65535 {
        if !bound.contains_key(&port) {
            bound.insert(port, socket.clone());
            drop(bound);
            let mut sock = socket.lock();
            sock.local_addr = Some(SocketAddrV4::new(addr, port));
            return true;
        }
    }
    false
}

pub fn find_socket(port: u16, _addr: u32) -> Option<Arc<Mutex<Socket>>> {
    BOUND_SOCKETS.lock().get(&port).cloned()
}

pub fn register_listener(port: u16, socket: Arc<Mutex<Socket>>) {
    TCP_LISTENER.lock().insert(port, socket);
}

pub fn find_listener(port: u16) -> Option<Arc<Mutex<Socket>>> {
    TCP_LISTENER.lock().get(&port).cloned()

use core::arch::global_asm;
use core::sync::atomic::{AtomicU32, Ordering};

use crate::arch::shared::hart::MAX_HARTS;

const BOOT_STACK_SIZE: usize = 4096 * 32;
const BOOT_STACK_SHIFT: usize = BOOT_STACK_SIZE.trailing_zeros() as usize;

#[repr(C, align(16))]
struct BootStack([u8; BOOT_STACK_SIZE]);

/// Per-hart boot stacks. Each secondary hart parks on its own stack until
/// the boot hart publishes readiness.
#[unsafe(link_section = ".bss.stack")]
static BOOT_STACKS: [BootStack; MAX_HARTS] =
    [const { BootStack([0u8; BOOT_STACK_SIZE]) }; MAX_HARTS];

/// Per-hart saved hart IDs — each hart writes its own slot. No race.
#[unsafe(no_mangle)]
#[unsafe(link_section = ".data")]
pub(super) static SAVED_HART_IDS: [u64; MAX_HARTS] = [0u64; MAX_HARTS];

/// Boot hart claim sentinel. Set to u64::MAX initially; the first hart to
/// atomically claim it (via LR/SC) becomes the boot hart.
#[unsafe(no_mangle)]
#[unsafe(link_section = ".data")]
static BOOT_HART_ID_STATIC: u64 = u64::MAX;

/// Flag set by the boot hart after all init is complete. Parked secondaries
/// spin on this with `fence r, r` before calling `smp_secondary_entry`.
#[unsafe(no_mangle)]
#[unsafe(link_section = ".data")]
static BOOT_READY_FLAG: AtomicU32 = AtomicU32::new(0);

pub fn set_boot_hart_id_for_entry(_id: u64) {
    // No-op: the LR/SC atomic claim in _start replaces this.
}

/// Called by the boot hart after all kernel init is complete.
/// Releases parked secondary harts.
pub fn publish_boot_ready() {
    BOOT_READY_FLAG.store(1, Ordering::Release);
}

global_asm!(
    r"
    .section .text.entry
    .option push
    .option arch, +zalrsc
    .globl _start
    .globl _secondary_start
_start:
_secondary_start:
    // Save bootloader args.
    mv   t1, a0
    mv   t2, a1
    mv   t3, a2

    // Write hart ID to per-hart slot: SAVED_HART_IDS[hart_id].
    la   t0, {saved_hart_ids}
    slli t4, t1, 3
    add  t0, t0, t4
    sd   t1, 0(t0)

    // Zero tp (will be set by bootstrap_hart_local).
    li   t4, 0
    mv   tp, t4

    // Set up per-hart boot stack: sp = BOOT_STACKS + hart_id * BOOT_STACK_SIZE.
    la   t5, {boot_stacks}
    li   t6, {stack_size}
    slli t4, t1, {stack_shift}
    add  sp, t5, t4
    add  sp, sp, t6

    // --- LR/SC atomic claim for boot hart ---
    // BOOT_HART_ID_STATIC starts at u64::MAX (sentinel = unclaimed).
    // First hart to SC.d wins boot-hart status.
    la   t0, {boot_hart_id}
    li   t5, -1               // sentinel: u64::MAX

1:  lr.d t4, (t0)             // load-reserved
    bne  t4, t5, 2f           // already claimed — someone else is boot hart

    sc.d t6, t1, (t0)         // store-conditional: claim with my hart_id
    bnez t6, 1b               // SC failed, retry
    j    3f                   // claimed — I am boot hart

    // Lost claim or boot hart already decided.
2:  beq  t1, t4, 3f           // claimed boot hart ID == my ID → I am boot hart

    // --- Secondary hart: park until boot hart publishes readiness ---
    la   t0, {boot_ready}
4:  lw   t5, 0(t0)            // load BOOT_READY_FLAG
    fence r, r                 // acquire barrier — observe boot hart's writes
    beqz t5, 4b                // spin until flag is set

    mv   a0, t1
    call {secondary_entry}

    // --- Boot hart path ---
3:  mv   a0, t1
    mv   a1, t2
    mv   a2, t3
    call {main}
    .option pop
",
    boot_stacks = sym BOOT_STACKS,
    stack_size = const BOOT_STACK_SIZE,
    stack_shift = const BOOT_STACK_SHIFT,
    main = sym crate::main,
    secondary_entry = sym crate::smp::boot::smp_secondary_entry,
    boot_hart_id = sym BOOT_HART_ID_STATIC,
    boot_ready = sym BOOT_READY_FLAG,
    saved_hart_ids = sym SAVED_HART_IDS,
);

