/// Update the per-hart user sp slot consumed by the normal trap-return path.
pub fn set_trap_return_user_sp(user_sp: u64) {
    unsafe {
        core::arch::asm!(
            "csrw sscratch, {sp}",
            sp = in(reg) user_sp,
            options(nostack),
        );
    }
}

/// Point `sscratch` back at the hart trap page before a kernel thread enables
/// interrupts. User trap return paths overwrite `sscratch` with the user trap
/// frame, so a later idle timer interrupt needs this reset to enter safely.
pub fn prepare_idle_trap_frame() {
    let hart_id = crate::arch::current_hart_id();
    let trap_page = crate::arch::shared::trap_page::trap_page(hart_id)
        .expect("prepare_idle_trap_frame: trap page not initialized");

    let sp: usize;
    let tp: usize;
    unsafe {
        core::arch::asm!("mv {}, sp", out(reg) sp, options(nomem, nostack));
        core::arch::asm!("mv {}, tp", out(reg) tp, options(nomem, nostack));
    }

    let frame = trap_page as *mut TrapFrame;
    unsafe {
        (*frame).kernel_sp = sp as u64;
        (*frame).kernel_tp = tp as u64;
        core::arch::asm!(
            "csrw sscratch, {trap_page}",
            trap_page = in(reg) trap_page,
            options(nostack),
        );
    }
}

/// Boot secondary harts discovered from firmware.
pub fn arch_smp_boot_secondaries() {
    let boot_hart = crate::smp::boot_hart_id();
    for hart_id in 0..crate::smp::MAX_HARTS {
        if crate::smp::is_discovered(hart_id) && hart_id != boot_hart {
            crate::smp::smp_boot_secondary(hart_id).ok();
        }
    }
}

//! Process table: per-bucket Mutex hash table mapping Pid → Process.

use crate::sync::IrqSafeSpinlock;
use alloc::boxed::Box;
use alloc::sync::Arc;
use alloc::vec::Vec;

use super::Process;
use crate::util::SpinMutex;

const PROCESS_TABLE_BUCKETS: usize = 64;

struct ListNode<T> {
    key: usize,
    next: Option<*mut ListNode<T>>,
    value: T,
}

struct Bucket<T> {
    head: Option<*mut ListNode<T>>,
}

impl<T> Bucket<T> {
    const fn new() -> Self {
        Self { head: None }
    }
}

pub struct ProcessTable {
    buckets: [IrqSafeSpinlock<Bucket<Arc<SpinMutex<Process>>>>; PROCESS_TABLE_BUCKETS],
}

impl ProcessTable {
    pub const fn new() -> Self {
        Self {
            buckets: [const { IrqSafeSpinlock::new(Bucket::new()) }; PROCESS_TABLE_BUCKETS],
        }
    }

    fn bucket_index(pid: usize) -> usize {
        pid % PROCESS_TABLE_BUCKETS
    }

    pub fn insert(&self, pid: usize, proc: Arc<SpinMutex<Process>>) -> Result<(), &'static str> {
        let idx = Self::bucket_index(pid);
        let mut new_node = Some(Box::new(ListNode {
            key: pid,
            next: None,
            value: proc,
        }));
        let mut bucket = self.buckets[idx].lock();

        let mut curr = bucket.head;
        while let Some(node_ptr) = curr {
            let node = unsafe { &*node_ptr };
            if node.key == pid {
                return Err("process with this PID already exists");
            }
            curr = node.next;
        }

        let mut node = new_node.take().expect("new process table node missing");
        node.next = bucket.head;
        let node_ptr = Box::into_raw(node);
        bucket.head = Some(node_ptr);
        Ok(())
    }

    pub fn remove(&self, pid: usize) -> Option<Arc<SpinMutex<Process>>> {
        let idx = Self::bucket_index(pid);
        let mut bucket = self.buckets[idx].lock();

        let mut prev: Option<*mut ListNode<Arc<SpinMutex<Process>>>> = None;
        let mut curr = bucket.head;

        while let Some(node_ptr) = curr {
            let node = unsafe { &*node_ptr };
            if node.key == pid {
                let next = node.next;
                match prev {
                    None => bucket.head = next,
                    Some(prev_ptr) => unsafe { (*prev_ptr).next = next },
                }
                return Some(unsafe {
                    let val = Arc::clone(&(*node_ptr).value);
                    drop(Box::from_raw(node_ptr));
                    val
                });
            }
            prev = curr;
            curr = node.next;
        }
        None
    }

    pub fn get(&self, pid: usize) -> Option<Arc<SpinMutex<Process>>> {
        let idx = Self::bucket_index(pid);
        let bucket = self.buckets[idx].lock();

        let mut curr = bucket.head;
        while let Some(node_ptr) = curr {
            let node = unsafe { &*node_ptr };
            if node.key == pid {
                return Some(Arc::clone(&node.value));
            }
            curr = node.next;
        }
        None
    }

    pub fn with<F, R>(&self, pid: usize, f: F) -> Option<R>
    where
        F: FnOnce(&Process) -> R,
    {
        self.get(pid).map(|proc| f(&*proc.lock()))
    }

    pub fn with_mut<F, R>(&self, pid: usize, f: F) -> Option<R>
    where
        F: FnOnce(&mut Process) -> R,
    {
        self.get(pid).map(|proc| f(&mut *proc.lock()))
    }

    pub fn for_each(&self, mut f: impl FnMut(usize, Arc<SpinMutex<Process>>)) {
        let mut snapshots: Vec<Arc<SpinMutex<Process>>> = Vec::new();
        for i in 0..PROCESS_TABLE_BUCKETS {
            let bucket = self.buckets[i].lock();
            let mut curr = bucket.head;
            while let Some(node_ptr) = curr {
                let node = unsafe { &*node_ptr };
                snapshots.push(Arc::clone(&node.value));
                curr = node.next;
            }
        }
        for proc in snapshots {
            let pid = proc.lock().pid;
            f(pid as usize, proc);
        }
    }
}

