    use core::sync::atomic::AtomicU32;
    use scarlet_test_macros::scarlet_test;

    fn make_test_process(pid: u32) -> Arc<SpinMutex<Process>> {
        Arc::new(SpinMutex::new(Process {
            pid,
            name: "test",
            parent: None,
            children: alloc::vec::Vec::new(),
            mm: None,
            threads: alloc::vec::Vec::new(),
            exit_status: None,
            running_tid: AtomicU32::new(0),
            pending_free_trap_pa: None,
            files: None,
            brk: 0,
            brk_base: 0,
            mmap_cursor: 0,
            cwd: alloc::string::String::from("/"),
            signal_actions: [crate::signal::SigAction::Default; crate::signal::SIG_N],
            zombie_children: alloc::vec::Vec::new(),
            child_waiters: alloc::vec::Vec::new(),
            uid: 0,
            euid: 0,
            gid: 0,
            egid: 0,
            umask: 0o022,
            suid: 0,
            sgid: 0,
            fsuid: 0,
            fsgid: 0,
        }))
    }

    #[scarlet_test]
    fn insert_get_roundtrip() {
        let table = ProcessTable::new();
        let proc = make_test_process(1);
        table.insert(1, Arc::clone(&proc)).unwrap();
        let got = table.get(1);
        assert!(got.is_some());
        assert_eq!(got.unwrap().lock().pid, 1);
    }

    #[scarlet_test]
    fn insert_duplicate_pid() {
        let table = ProcessTable::new();
        let p1 = make_test_process(1);
        let p2 = make_test_process(1);
        table.insert(1, p1).unwrap();
        let result = table.insert(1, p2);
        assert!(result.is_err());
    }

    #[scarlet_test]
    fn get_remove_missing() {
        let table = ProcessTable::new();
        assert!(table.get(999).is_none());
        assert!(table.remove(999).is_none());
    }

    #[scarlet_test]
    fn remove_existing() {
        let table = ProcessTable::new();
        let proc = make_test_process(42);
        table.insert(42, proc).unwrap();
        let removed = table.remove(42);
        assert!(removed.is_some());
        assert_eq!(removed.unwrap().lock().pid, 42);
        assert!(table.get(42).is_none());
    }

    #[scarlet_test]
    fn with_readonly_returns_value() {
        let table = ProcessTable::new();
        let proc = make_test_process(5);
        table.insert(5, proc).unwrap();
        let pid = table.with(5, |p| p.pid);
        assert_eq!(pid, Some(5));
    }

    #[scarlet_test]
    fn with_mut_modifies() {
        let table = ProcessTable::new();
        let proc = make_test_process(7);
        table.insert(7, proc).unwrap();
        let result = table.with_mut(7, |p| {
            p.exit_status = Some(crate::process::ExitStatus::from_exit_code(42));
            p.exit_status
        });
        assert_eq!(
            result,
            Some(Some(crate::process::ExitStatus::from_exit_code(42)))
        );
        assert_eq!(
            table.get(7).unwrap().lock().exit_status,
            Some(crate::process::ExitStatus::from_exit_code(42))
        );
    }

    #[scarlet_test]
    fn hash_collision_same_bucket() {
        let table = ProcessTable::new();
        let p1 = make_test_process(64); // bucket 0
        let p2 = make_test_process(128); // bucket 0
        table.insert(64, p1).unwrap();
        table.insert(128, p2).unwrap();
        let g1 = table.get(64).unwrap();
        let g2 = table.get(128).unwrap();
        assert_eq!(g1.lock().pid, 64);
        assert_eq!(g2.lock().pid, 128);
    }
}

//! Thread table: per-bucket Mutex hash table mapping Tid → Thread.

use crate::sync::IrqSafeSpinlock;
use alloc::boxed::Box;
use alloc::sync::Arc;
use alloc::vec::Vec;

use super::Thread;
use crate::util::SpinMutex;

const THREAD_TABLE_BUCKETS: usize = 256;

struct ListNode<T> {
    key: usize,
    next: Option<*mut ListNode<T>>,
    value: T,
}

struct Bucket<T> {
    head: Option<*mut ListNode<T>>,
}

impl<T> Bucket<T> {
    const fn new() -> Self {
        Self { head: None }
    }
}

pub struct ThreadTable {
    buckets: [IrqSafeSpinlock<Bucket<Arc<SpinMutex<Thread>>>>; THREAD_TABLE_BUCKETS],
}

impl ThreadTable {
    pub const fn new() -> Self {
        Self {
            buckets: [const { IrqSafeSpinlock::new(Bucket::new()) }; THREAD_TABLE_BUCKETS],
        }
    }

    fn bucket_index(tid: usize) -> usize {
        tid % THREAD_TABLE_BUCKETS
    }

    pub fn insert(&self, tid: usize, thread: Arc<SpinMutex<Thread>>) -> Result<(), &'static str> {
        let idx = Self::bucket_index(tid);
        let mut new_node = Some(Box::new(ListNode {
            key: tid,
            next: None,
            value: thread,
        }));
        let mut bucket = self.buckets[idx].lock();

        let mut curr = bucket.head;
        while let Some(node_ptr) = curr {
            let node = unsafe { &*node_ptr };
            if node.key == tid {
                return Err("thread with this TID already exists");
            }
            curr = node.next;
        }

        let mut node = new_node.take().expect("new thread table node missing");
        node.next = bucket.head;
        let node_ptr = Box::into_raw(node);
        bucket.head = Some(node_ptr);
        Ok(())
    }

    pub fn remove(&self, tid: usize) -> Option<Arc<SpinMutex<Thread>>> {
        let idx = Self::bucket_index(tid);
        let mut bucket = self.buckets[idx].lock();

        let mut prev: Option<*mut ListNode<Arc<SpinMutex<Thread>>>> = None;
        let mut curr = bucket.head;

        while let Some(node_ptr) = curr {
            let node = unsafe { &*node_ptr };
            if node.key == tid {
                let next = node.next;
                match prev {
                    None => bucket.head = next,
                    Some(prev_ptr) => unsafe { (*prev_ptr).next = next },
                }
                return Some(unsafe {
                    let val = Arc::clone(&(*node_ptr).value);
                    drop(Box::from_raw(node_ptr));
                    val
                });
            }
            prev = curr;
            curr = node.next;
        }
        None
    }

    pub fn get(&self, tid: usize) -> Option<Arc<SpinMutex<Thread>>> {
        let idx = Self::bucket_index(tid);
        let bucket = self.buckets[idx].lock();

        let mut curr = bucket.head;
        while let Some(node_ptr) = curr {
            let node = unsafe { &*node_ptr };
            if node.key == tid {
                return Some(Arc::clone(&node.value));
            }
            curr = node.next;
        }
        None
    }

    pub fn with_mut<F, R>(&self, tid: usize, f: F) -> Option<R>
    where
        F: FnOnce(&mut Thread) -> R,
    {
        self.get(tid).map(|thread| f(&mut *thread.lock()))
    }

    /// Iterate over all threads without holding bucket locks while invoking
    /// the callback. This avoids bucket-lock/thread-lock order inversions.
    pub fn for_each(&self, mut f: impl FnMut(usize, &Thread)) {
        let mut snapshots: Vec<Arc<SpinMutex<Thread>>> = Vec::new();
        for bucket in &self.buckets {
            let guard = bucket.lock();
            let mut curr = guard.head;
            while let Some(node_ptr) = curr {
                let node = unsafe { &*node_ptr };
                snapshots.push(Arc::clone(&node.value));
                curr = node.next;
            }
        }
        for thread in snapshots {
            let thread_guard = thread.lock();
            let tid = thread_guard.tid;
            f(tid as usize, &*thread_guard);
        }
    }
}

