//! Time-related syscalls: clock_gettime, gettimeofday, nanosleep.
//! Backed by the `tokei` clock subsystem.

use crate::arch::shared::syscall::SyscallRequest;
use crate::syscall::errno::Errno;
use crate::tokei;

const TIMER_ABSTIME: usize = 1;

fn checked_user_addr(base: u64, offset: usize) -> Option<u64> {
    base.checked_add(offset as u64)
}

pub fn sys_clock_gettime(req: &SyscallRequest) -> isize {
    let clock_id = req.arg0;
    let ts_ptr = req.arg1 as u64;

    let ns = match clock_id {
        0 | 1 => tokei::current_time_ns(),
        _ => return Errno::EINVAL.as_ret(),
    };

    write_timespec(ts_ptr, ns)
}

pub fn sys_gettimeofday(req: &SyscallRequest) -> isize {
    let tv_ptr = req.arg0 as u64;
    let tz_ptr = req.arg1 as u64;
    let ns = tokei::current_time_ns();
    if tv_ptr != 0 {
        let ret = write_timeval(tv_ptr, ns);
        if ret < 0 {
            return ret;
        }
    }
    if tz_ptr != 0 {
        let ret = write_timezone(tz_ptr);
        if ret < 0 {
            return ret;
        }
    }
    0
}

pub fn sys_clock_getres(req: &SyscallRequest) -> isize {
    let clock_id = req.arg0;
    let res_ptr = req.arg1 as u64;

    // Validate clock_id; Linux allows NULL res_ptr (success with no output).
    match clock_id {
        0 | 1 => {}
        _ => return Errno::EINVAL.as_ret(),
    }

    if res_ptr == 0 {
        return 0;
    }
    // tokei resolution is 1 ns.
    write_timespec(res_ptr, 1)
}

pub fn sys_clock_nanosleep(req: &SyscallRequest) -> isize {
    let clock_id = req.arg0;
    let flags = req.arg1;
    let req_ptr = req.arg2 as u64;
    let rem_ptr = req.arg3 as u64;

    // Only CLOCK_REALTIME (0) and CLOCK_MONOTONIC (1) are supported.
    match clock_id {
        0 | 1 => {}
        _ => return Errno::EINVAL.as_ret(),
    }

    if flags & !TIMER_ABSTIME != 0 {
        return Errno::EINVAL.as_ret();
    }

    if flags & TIMER_ABSTIME != 0 {
        return sys_clock_nanosleep_abstime(req_ptr);
    }

    sys_nanosleep_inner(req_ptr, rem_ptr)
}

pub fn sys_nanosleep(req: &SyscallRequest) -> isize {
    let req_ptr = req.arg0 as u64;
    let rem_ptr = req.arg1 as u64;
    sys_nanosleep_inner(req_ptr, rem_ptr)
}

fn sys_nanosleep_inner(req_ptr: u64, _rem_ptr: u64) -> isize {
    let req_ns = match read_timespec(req_ptr) {
        Ok(ns) => ns,
        Err(e) => return e,
    };
    if req_ns == 0 {
        return 0;
    }

    let deadline_ns = tokei::current_time_ns().saturating_add(req_ns);
    sleep_until_deadline(deadline_ns)
}

fn sys_clock_nanosleep_abstime(req_ptr: u64) -> isize {
    let deadline_ns = match read_timespec(req_ptr) {
        Ok(ns) => ns,
        Err(e) => return e,
    };

    tokei::refresh_timekeeper();
    if deadline_ns <= tokei::current_time_ns() {
        return 0;
    }

    sleep_until_deadline(deadline_ns)
}

fn sleep_until_deadline(deadline_ns: u64) -> isize {
    if !matches!(crate::sched::current_tid(), Some(tid) if tid != 0) {
        return Errno::EFAULT.as_ret();
    }

    loop {
        tokei::refresh_timekeeper();
        if tokei::current_time_ns() >= deadline_ns {
            return 0;
        }
        crate::sched::yield_current();
    }
}

// ── user-memory copy helpers (page-boundary safe) ────────────────────────

/// Read `len` bytes from user `user_ptr` into `dst`, validating each page for user-read access.
fn copy_from_user(
    mm: &crate::mm::memory_set::MemorySet,
    user_ptr: u64,
    dst: &mut [u8],
) -> Result<(), isize> {
    let mut remaining = dst.len();
    let mut va = user_ptr;
    let mut offset = 0;
    while remaining > 0 {
        let pa = mm.translate_user_read(va).ok_or(Errno::EFAULT.as_ret())?;
        let page_off = (va as usize) & (crate::mm::PAGE_SIZE - 1);
        let chunk = core::cmp::min(remaining, crate::mm::PAGE_SIZE - page_off);
        let src_slice = unsafe { core::slice::from_raw_parts(pa as *const u8, chunk) };
        dst[offset..offset + chunk].copy_from_slice(src_slice);
        remaining -= chunk;
        offset += chunk;
        if remaining > 0 {
            va = checked_user_addr(va, chunk).ok_or(Errno::EFAULT.as_ret())?;
        }
    }
    Ok(())
}

// ── typed helpers ────────────────────────────────────────────────────────

/// Write `struct timespec { tv_sec: u64, tv_nsec: u64 }` (16 bytes) to user memory.
/// Validates each page for user-write access.
fn write_timespec(ptr: u64, ns: u64) -> isize {
    let tv_sec = (ns / 1_000_000_000) as u64;
    let tv_nsec = (ns % 1_000_000_000) as u64;

    let mut buf = [0u8; 16];
    buf[0..8].copy_from_slice(&tv_sec.to_ne_bytes());
    buf[8..16].copy_from_slice(&tv_nsec.to_ne_bytes());

    if crate::syscall::sched::write_user_bytes_cow(&buf, ptr) {
        0
    } else {
        Errno::EFAULT.as_ret()
    }
}

/// Write `struct timeval { tv_sec: u64, tv_usec: u64 }` (16 bytes) to user memory.
/// Validates each page for user-write access.
fn write_timeval(ptr: u64, ns: u64) -> isize {
    let tv_sec = (ns / 1_000_000_000) as u64;
    let tv_usec = ((ns % 1_000_000_000) / 1_000) as u64;

    let mut buf = [0u8; 16];
    buf[0..8].copy_from_slice(&tv_sec.to_ne_bytes());
    buf[8..16].copy_from_slice(&tv_usec.to_ne_bytes());

    if crate::syscall::sched::write_user_bytes_cow(&buf, ptr) {
        0
    } else {
        Errno::EFAULT.as_ret()
    }
}

/// Write legacy `struct timezone { int tz_minuteswest; int tz_dsttime }`.
/// Linux keeps this ABI for compatibility; Scarlet reports UTC/no DST.
fn write_timezone(ptr: u64) -> isize {
    let buf = [0u8; 8];
    if crate::syscall::sched::write_user_bytes_cow(&buf, ptr) {
        0
    } else {
        Errno::EFAULT.as_ret()
    }
}

/// Read `struct timespec { tv_sec: u64, tv_nsec: u64 }` (16 bytes) from user memory.
/// Returns total nanoseconds, or a negative errno on failure.
fn read_timespec(ptr: u64) -> Result<u64, isize> {
    let mut buf = [0u8; 16];

    let tid = crate::sched::current_tid().unwrap_or(0);
    crate::process::with_thread(tid as crate::process::Tid, |thread| {
        let proc = thread.proc.as_ref()?.upgrade()?;
        let proc_guard = proc.lock();
        let mm = proc_guard.mm.as_ref()?;
        match copy_from_user(mm, ptr, &mut buf) {
            Ok(()) => {
                // Safe: buf[0..8] and buf[8..16] are exactly 8 bytes each,
                // so try_into::<[u8; 8]>() always succeeds.
                let tv_sec = i64::from_ne_bytes(buf[0..8].try_into().unwrap());
                let tv_nsec = i64::from_ne_bytes(buf[8..16].try_into().unwrap());
                if tv_sec < 0 || tv_nsec < 0 || tv_nsec >= 1_000_000_000 {
                    return Some(Err(Errno::EINVAL.as_ret()));
                }
                let ns = (tv_sec as u64)
                    .saturating_mul(1_000_000_000)
                    .saturating_add(tv_nsec as u64);
                Some(Ok(ns))
            }
            Err(e) => Some(Err(e)),
        }
    })
    .flatten()
    .unwrap_or(Err(Errno::EFAULT.as_ret()))
}

// ── getitimer / setitimer ──────────────────────────────────────────────────

const ITIMER_REAL: usize = 0;

pub fn sys_getitimer(req: &SyscallRequest) -> isize {
    let which = req.arg0;
    let curr_ptr = req.arg1 as u64;

    if which != ITIMER_REAL {
        return Errno::ENOSYS.as_ret();
    }

    write_timeval_pair(curr_ptr, 0, 0, 0, 0)
}

pub fn sys_setitimer(req: &SyscallRequest) -> isize {
    let which = req.arg0;
    let new_ptr = req.arg1 as u64;
    let old_ptr = req.arg2 as u64;

    if which != ITIMER_REAL {
        return Errno::ENOSYS.as_ret();
    }

    let (new_value_us, new_interval_us) = match read_timeval_pair(new_ptr) {
        Ok(v) => v,
