/// Update the per-hart user sp slot consumed by the normal trap-return path.
pub fn set_trap_return_user_sp(user_sp: u64) {
    unsafe {
        core::arch::asm!(
            "csrwr {sp}, 0x30",
            sp = in(reg) user_sp,
            options(nostack),
        );
    }
}

/// Point CSR_SAVE0 back at the hart trap page before a kernel thread enables
/// interrupts. The LoongArch trap entry also expects the kernel `tp` pointer at
/// the top of the trap page.
pub fn prepare_idle_trap_frame() -> usize {
    let hart_id = crate::arch::current_hart_id();
    let trap_page = crate::arch::shared::trap_page::trap_page(hart_id)
        .expect("prepare_idle_trap_frame: trap page not initialized");

    let tp: usize;
    unsafe {
        core::arch::asm!("move {}, $tp", out(reg) tp, options(nomem, nostack));
        ((trap_page + 4096 - core::mem::size_of::<usize>()) as *mut usize).write(tp);
        core::arch::asm!(
            "move  $t0, {trap_page}",
            "csrwr $t0, 0x30",
            "move  $t0, {tp}",
            "csrwr $t0, 0x32",
            trap_page = in(reg) trap_page,
            tp = in(reg) tp,
            out("$t0") _,
            options(nostack),
        );
        core::arch::asm!(
            "move  $t0, {trap_page}",
            "csrwr $t0, 0x33",
            trap_page = in(reg) trap_page,
            out("$t0") _,
            options(nomem, nostack),
        );
    }
    trap_page
}

