//! Fair scheduling class: priority-weighted round-robin with bounded wait.
//!
//! 8 priority levels (0 = highest). Each level is a FIFO queue.
//! Pick policy uses weighted service rounds so lower priorities still run.
//! Time slice = (priority + 1) * BASE_SLICE ticks.

use super::class::SchedClass;

/// Number of priority levels.
pub const NUM_PRIORITIES: usize = 8;

/// Base time slice in timer ticks (1 tick = 10ms at 100Hz).
const BASE_SLICE: usize = 1;

/// Maximum number of fair tasks tracked per hart run queue.
///
/// Tests instantiate large scheduler state snapshots on stack; keep the
/// test-only capacity smaller to avoid stack overflow in qemu test kernels.
#[cfg(test)]
const MAX_TRACKED_FAIR_TASKS: usize = 512;
#[cfg(not(test))]
const MAX_TRACKED_FAIR_TASKS: usize = 4096;

const ENTRY_EMPTY: u8 = 0;
const ENTRY_FULL: u8 = 1;
const NONE_INDEX: usize = usize::MAX;

#[cfg(target_pointer_width = "64")]
const HASH_MULTIPLIER: usize = 0x9E37_79B9_7F4A_7C15;
#[cfg(target_pointer_width = "32")]
const HASH_MULTIPLIER: usize = 0x9E37_79B9;

#[derive(Clone, Copy)]
struct TaskEntry {
    tid: usize,
    state: u8,
    queued: bool,
    priority: u8,
    slice: usize,
    prev: usize,
    next: usize,
}

impl TaskEntry {
    const fn empty() -> Self {
        Self {
            tid: 0,
            state: ENTRY_EMPTY,
            queued: false,
            priority: 0,
            slice: 0,
            prev: NONE_INDEX,
            next: NONE_INDEX,
        }
    }
}

#[derive(Clone, Copy)]
pub struct RunnableCursor {
    priority: usize,
    next_entry: usize,
    initialized: bool,
}

impl RunnableCursor {
    pub const fn new() -> Self {
        Self {
            priority: 0,
            next_entry: NONE_INDEX,
            initialized: false,
        }
    }
}

pub struct FairSchedClass {
    /// Per-priority FIFO run queue head/tail indices into `entries`.
    queue_head: [usize; NUM_PRIORITIES],
    queue_tail: [usize; NUM_PRIORITIES],
    /// Fixed-capacity slot table keyed by TID via open addressing.
    entries: [TaskEntry; MAX_TRACKED_FAIR_TASKS],
    /// Number of runnable tasks.
    nr_running: usize,
    /// Per-priority weighted pick budget for the current service cycle.
    pick_budget: [usize; NUM_PRIORITIES],
    /// Round-robin cursor over priority levels.
    pick_cursor: usize,
    /// Guard rail warning flag when the slot table is full.
    table_full_warned: bool,
}

impl FairSchedClass {
    pub const fn new() -> Self {
        Self {
            queue_head: [NONE_INDEX; NUM_PRIORITIES],
            queue_tail: [NONE_INDEX; NUM_PRIORITIES],
            entries: [TaskEntry::empty(); MAX_TRACKED_FAIR_TASKS],
            nr_running: 0,
            pick_budget: [0; NUM_PRIORITIES],
            pick_cursor: 0,
            table_full_warned: false,
        }
    }

    fn clamp_priority(priority: usize) -> usize {
        if priority >= NUM_PRIORITIES {
            NUM_PRIORITIES - 1
        } else {
            priority
        }
    }

    /// Compute the time slice for a given priority level.
    fn time_slice_for(priority: usize) -> usize {
        let prio = Self::clamp_priority(priority);
        (prio + 1) * BASE_SLICE
    }

    /// Higher priority gets larger budget share per service cycle.
    fn priority_weight(priority: usize) -> usize {
        NUM_PRIORITIES - priority
    }

    fn refill_pick_budget(&mut self) {
        let mut prio = 0usize;
        while prio < NUM_PRIORITIES {
            self.pick_budget[prio] = Self::priority_weight(prio);
            prio += 1;
        }
    }

    fn has_remaining_budget(&self) -> bool {
        self.pick_budget.iter().any(|&budget| budget > 0)
    }

    fn hash_tid(tid: usize) -> usize {
        tid.wrapping_mul(HASH_MULTIPLIER) % MAX_TRACKED_FAIR_TASKS
    }

    fn find_entry(&self, tid: usize) -> Option<usize> {
        let mut index = Self::hash_tid(tid);
        let mut probes = 0usize;
        while probes < MAX_TRACKED_FAIR_TASKS {
            let entry = self.entries[index];
            if entry.state == ENTRY_EMPTY {
                return None;
            }
            if entry.state == ENTRY_FULL && entry.tid == tid {
                return Some(index);
            }
            index = (index + 1) % MAX_TRACKED_FAIR_TASKS;
            probes += 1;
        }
        None
    }

    fn claim_entry_slot(&mut self, tid: usize) -> Option<usize> {
        let mut index = Self::hash_tid(tid);
        let mut probes = 0usize;
        while probes < MAX_TRACKED_FAIR_TASKS {
            match self.entries[index].state {
                ENTRY_EMPTY => return Some(index),
                ENTRY_FULL => {
                    if self.entries[index].tid == tid {
                        return Some(index);
                    }
                }
                _ => {}
            }
            index = (index + 1) % MAX_TRACKED_FAIR_TASKS;
            probes += 1;
        }
        None
    }

    fn link_to_tail(&mut self, priority: usize, entry_index: usize) {
        let tail = self.queue_tail[priority];
        self.entries[entry_index].prev = tail;
        self.entries[entry_index].next = NONE_INDEX;
        if tail == NONE_INDEX {
            self.queue_head[priority] = entry_index;
        } else {
            self.entries[tail].next = entry_index;
        }
        self.queue_tail[priority] = entry_index;
    }

    fn unlink_from_queue(&mut self, entry_index: usize) {
        let priority = self.entries[entry_index].priority as usize;
        let prev = self.entries[entry_index].prev;
        let next = self.entries[entry_index].next;

        if prev == NONE_INDEX {
            self.queue_head[priority] = next;
        } else {
            self.entries[prev].next = next;
        }

        if next == NONE_INDEX {
            self.queue_tail[priority] = prev;
        } else {
