//! IPv4 protocol implementation.
//!
//! Handles IPv4 packet parsing, routing, and dispatch to transport-layer
//! protocols (TCP, UDP).

use crate::net::arp;
use crate::net::buffer::NetworkBuffer;
use crate::net::ethernet::ETHERTYPE_IPV4;
use crate::net::tcp;
use crate::net::udp;
use crate::sync::IrqSafeSpinlock;
use alloc::vec::Vec;

pub const IP_HDR_LEN: usize = 20;
pub const IP_PROTO_ICMP: u8 = 1;
pub const IP_PROTO_TCP: u8 = 6;
pub const IP_PROTO_UDP: u8 = 17;

static LOOPBACK_QUEUE: IrqSafeSpinlock<Vec<NetworkBuffer>> = IrqSafeSpinlock::new(Vec::new());

pub fn init() {
    info!("net/ipv4: initialized");
}

/// Process a received IPv4 packet.
pub fn receive(mut buf: NetworkBuffer) {
    let payload = buf.payload();
    if payload.len() < IP_HDR_LEN {
        return;
    }

    let version_ihl = payload[0];
    let version = version_ihl >> 4;
    if version != 4 {
        return;
    }
    let ihl = (version_ihl & 0x0f) as usize * 4;
    if ihl < IP_HDR_LEN || ihl > payload.len() {
        return;
    }

    let total_len = ((payload[2] as usize) << 8) | (payload[3] as usize);
    if total_len < ihl || total_len > payload.len() {
        return;
    }

    let protocol = payload[9];
    let checksum = ((payload[10] as u16) << 8) | (payload[11] as u16);

    let src_ip = u32::from_be_bytes([payload[12], payload[13], payload[14], payload[15]]);
    let dst_ip = u32::from_be_bytes([payload[16], payload[17], payload[18], payload[19]]);

    // Validate checksum (only on header)
    if checksum != 0 {
        let calc = ip_checksum(&payload[..ihl]);
        if calc != 0 {
            return;
        }
    }

    // Determine if this packet is for us
    let our_ip = arp::our_ip();
    if dst_ip != our_ip && dst_ip != 0xffffffff && dst_ip != 0 {
        // Not for us, and we don't route
        return;
    }

    // Strip IP header
    let l4_payload = payload[ihl..total_len].to_vec();
    let l4_buf = NetworkBuffer::new(l4_payload);

    match protocol {
        IP_PROTO_TCP => tcp::receive(l4_buf, src_ip, dst_ip),
        IP_PROTO_UDP => udp::receive(l4_buf, src_ip, dst_ip),
        IP_PROTO_ICMP => {} // Silently drop ICMP for now
        _ => {}
    }
}

/// Send an IPv4 packet to the specified destination.
pub fn send(dst_ip: u32, protocol: u8, mut payload: NetworkBuffer) {
    let src_ip = arp::our_ip();
    let total_len = IP_HDR_LEN + payload.payload_len();

    // Build IP header
    let mut header = [0u8; IP_HDR_LEN];
    header[0] = 0x45; // Version=4, IHL=5
    header[1] = 0; // DSCP + ECN
    header[2] = (total_len >> 8) as u8;
    header[3] = (total_len & 0xff) as u8;
    header[4] = 0; // Identification high
    header[5] = 0; // Identification low
    header[6] = 0x40; // Flags: Don't Fragment, Fragment offset high = 0
    header[7] = 0; // Fragment offset low
    header[8] = 64; // TTL
    header[9] = protocol;
    // Checksum at 10..12, computed below
    header[12..16].copy_from_slice(&src_ip.to_be_bytes());
    header[16..20].copy_from_slice(&dst_ip.to_be_bytes());

    // Compute header checksum
    let csum = ip_checksum(&header);
    header[10] = (csum >> 8) as u8;
    header[11] = (csum & 0xff) as u8;

    payload.prepend(&header);

    if dst_ip == src_ip {
        LOOPBACK_QUEUE.lock().push(payload);
        return;
    }

    // Resolve destination MAC via ARP
    if let Some(dst_mac) = arp::lookup(dst_ip) {
        crate::net::ethernet::send(dst_mac, ETHERTYPE_IPV4, payload.payload());
    } else {
        // Queue for ARP resolution, send ARP request
        arp::queue_pending(dst_ip, payload);
        arp::send_request(dst_ip);
    }
}

/// Internet checksum (ones' complement of ones' complement sum).
pub fn ip_checksum(data: &[u8]) -> u16 {
    let mut sum: u32 = 0;
    let mut i = 0;
    while i + 1 < data.len() {
        sum += ((data[i] as u32) << 8) | (data[i + 1] as u32);
        i += 2;
    }
    if i < data.len() {
        sum += (data[i] as u32) << 8;
    }
    while sum > 0xffff {
        sum = (sum & 0xffff) + (sum >> 16);
    }
    !(sum as u16)
}

pub fn drain_loopback() {
    loop {
        let packet = LOOPBACK_QUEUE.lock().pop();
        match packet {
            Some(pkt) => receive(pkt),
            None => break,
        }
    }
}

use alloc::sync::Arc;
use alloc::vec::Vec;
use core::sync::atomic::{AtomicBool, Ordering};

use crate::fs::Result;
use crate::fs::block::BlockDevice;

pub struct Ext4BlockAdapter {
    dev: Arc<dyn BlockDevice>,
    io_error: AtomicBool,
}

impl Ext4BlockAdapter {
    pub fn new(dev: Arc<dyn BlockDevice>) -> Self {
        Self {
            dev,
            io_error: AtomicBool::new(false),
        }
    }

    pub fn clear_error(&self) {
        self.io_error.store(false, Ordering::Release);
    }

    pub fn take_error(&self) -> bool {
        self.io_error.swap(false, Ordering::AcqRel)
    }

    fn record_error(&self) {
        self.io_error.store(true, Ordering::Release);
    }
}

impl ext4_rs::BlockDevice for Ext4BlockAdapter {
    fn read_offset(&self, offset: usize) -> Vec<u8> {
        let blk_size = self.dev.block_size();
        let read_size = 4096;
        let start_sector = offset / blk_size;
        let start_off = offset % blk_size;
        let end_offset = offset + read_size;
        let total_sectors = ((end_offset + blk_size - 1) / blk_size) - start_sector;

        let mut buf = alloc::vec![0u8; read_size];
        let mut buf_pos = 0;

        for i in 0..total_sectors {
            let sector = (start_sector + i) as u64;
            let mut sector_buf = alloc::vec![0u8; blk_size];
            if self.dev.read_block(sector, &mut sector_buf).is_err() {
                self.record_error();
                return buf;
            }

            let copy_start = if i == 0 { start_off } else { 0 };
            let remaining = read_size - buf_pos;
            let avail = blk_size - copy_start;
            let copy_len = remaining.min(avail);

            buf[buf_pos..buf_pos + copy_len]
                .copy_from_slice(&sector_buf[copy_start..copy_start + copy_len]);
            buf_pos += copy_len;
        }
        buf
    }

    fn write_offset(&self, offset: usize, data: &[u8]) {
        let blk_size = self.dev.block_size();
        let start_sector = (offset / blk_size) as u64;
        let start_off = offset % blk_size;
        let mut pos = 0;

        while pos < data.len() {
            let sector = start_sector + ((start_off + pos) / blk_size) as u64;
            let sec_off = (start_off + pos) % blk_size;
            let len = (data.len() - pos).min(blk_size - sec_off);

            let is_full_sector = sec_off == 0 && len == blk_size;

            if is_full_sector {
                if self.dev.write_block(sector, &data[pos..pos + len]).is_err() {
                    self.record_error();
                }
            } else {
                let mut sector_buf = alloc::vec![0u8; blk_size];
                if self.dev.read_block(sector, &mut sector_buf).is_err() {
                    self.record_error();
                } else {
                    sector_buf[sec_off..sec_off + len].copy_from_slice(&data[pos..pos + len]);
                    if self.dev.write_block(sector, &sector_buf).is_err() {
                        self.record_error();
                    }
                }
            }
            pos += len;
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use alloc::sync::Arc;
    use core::sync::atomic::{AtomicU64, Ordering};
    use ext4_rs::BlockDevice as _;
    use scarlet_test_macros::scarlet_test;

    struct MockBlk {
        block_size: usize,
        data: [u8; 4096],
        last_write: AtomicU64,
    }

    impl BlockDevice for MockBlk {
        fn block_size(&self) -> usize {
            self.block_size
        }
        fn num_blocks(&self) -> u64 {
            8
        }
        fn read_block(&self, _block_idx: u64, buf: &mut [u8]) -> Result<()> {
            let len = buf.len().min(self.data.len());
            buf[..len].copy_from_slice(&self.data[..len]);
            Ok(())
        }
        fn write_block(&self, block_idx: u64, _buf: &[u8]) -> Result<()> {
            self.last_write.store(block_idx, Ordering::Relaxed);
            Ok(())
        }
    }

    fn mkdev() -> (Arc<MockBlk>, Arc<dyn BlockDevice>) {
        let raw = Arc::new(MockBlk {
            block_size: 512,
            data: [0xAB; 4096],
            last_write: AtomicU64::new(u64::MAX),
        });
        let dev: Arc<dyn BlockDevice> = raw.clone();
        (raw, dev)
    }

    #[scarlet_test]
    fn adaptor_read_offset_reads_4096_bytes() {
        let (_, dev) = mkdev();
        let adaptor = Ext4BlockAdapter::new(dev);
        let data = adaptor.read_offset(0);
        assert_eq!(data.len(), 4096);
        assert_eq!(data[0], 0xAB);
        assert_eq!(data[4095], 0xAB);
        assert!(!adaptor.take_error());
    }

    #[scarlet_test]
    fn adaptor_read_offset_at_any_offset() {
        let (_, dev) = mkdev();
        let adaptor = Ext4BlockAdapter::new(dev);
        let data = adaptor.read_offset(1024);
        assert_eq!(data.len(), 4096);
        assert_eq!(data[0], 0xAB);
        assert!(!adaptor.take_error());
    }

    #[scarlet_test]
    fn adaptor_write_offset_issues_writes() {
        let (raw, dev) = mkdev();
        let adaptor = Ext4BlockAdapter::new(dev);
        let data = alloc::vec![0xCC; 2000];
        adaptor.write_offset(512, &data);
        assert_ne!(raw.last_write.load(Ordering::Relaxed), u64::MAX);
        assert!(!adaptor.take_error());
    }

    #[scarlet_test]
    fn adaptor_write_offset_at_offset_zero() {
        let (raw, dev) = mkdev();
        let adaptor = Ext4BlockAdapter::new(dev);
        adaptor.write_offset(0, &[0xCC; 100]);
        assert_ne!(raw.last_write.load(Ordering::Relaxed), u64::MAX);
        assert!(!adaptor.take_error());
    }

    #[scarlet_test]
    fn adaptor_read_offset_spans_multiple_sectors() {
        let (_, dev) = mkdev();
        let adaptor = Ext4BlockAdapter::new(dev);
        let data = adaptor.read_offset(0);
        assert_eq!(data.len(), 4096);
    }

    #[scarlet_test]
    fn adaptor_clear_and_take_error() {
        let (_, dev) = mkdev();
        let adaptor = Ext4BlockAdapter::new(dev);
        assert!(!adaptor.take_error());
        adaptor.record_error();
        assert!(adaptor.take_error());
        assert!(!adaptor.take_error());
    }
}

